','messages'=>['"%s" is now your featured artwork on the gallery overview.'=>'"%s" sasa ni kazi yako ya sanaa iliyoangaziwa kwenye muhtasari wa ghala.','#'=>'#','%1$d / %2$d'=>'%1$d / %2$d','%1$d admitted (%2$d opted out)'=>'%1$d wamekubaliwa (%2$d wamejitoa)','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d wamethibitishwa, %2$d wanasubiri uthibitisho, %3$d wamejiondoa, %4$d wamevurugika','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'Ujumbe %1$d kutoka kwa mtumaji ambaye hajajisajili umefichwa kutoka kwenye mwonekano huu. <a href="%2$s">Uutazame</a>.' . "\0" . 'Ujumbe %1$d kutoka kwa watumaji ambao hawajajisajili umefichwa kutoka kwenye mwonekano huu. <a href="%2$s">Uzitazame</a>.','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> ametuma ujumbe kwa jumuiya:','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s ameomba kujiunga na %2$s. Una siku %3$d za kupiga kura.','%1$s has confirmed their departure from %2$s.'=>'%1$s amethibitisha kuondoka kwao kutoka %2$s.','%1$s intro drafted for %2$s — review before it sends'=>'Utangulizi wa %1$s umeandikwa kwa %2$s — kagua kabla haijatumwa','%1$s must be %2$d characters or fewer.'=>'%1$s lazima iwe na herufi %2$d au chache zaidi.','%1$s Newsletter — %2$s'=>'Jarida la %1$s — %2$s','%1$s via %2$s'=>'%1$s kupitia %2$s','%1$s — %2$s'=>'%1$s — %2$s','%d application awaiting your vote'=>'Maombi %d yanasubiri kura yako' . "\0" . 'Maombi %d yanasubiri kura yako','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d ombi linasubiri uthibitisho wa barua pepe kutoka kwa mwombaji na bado halijaorodheshwa hapa chini.' . "\0" . '%d maombi yanasubiri uthibitisho wa barua pepe kutoka kwa waombaji na bado hayajaorodheshwa hapa chini.','%d community vote is open — check your email for your personal voting link.'=>'Kura ya jumuiya %d iko wazi — angalia barua pepe yako kwa kiungo chako binafsi cha kupigia kura.' . "\0" . '%d kura za jumuiya zimefunguliwa — angalia barua pepe yako kwa viungo vyako binafsi vya kupigia kura.','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'Maingizo %d kwa jumla. Kumbukumbu husafishwa kiotomatiki kulingana na mpangilio wa uhifadhi wa Inbox.','%d failed'=>'%d zimeshindwa' . "\0" . '%d zimeshindwa','%d more will see it in their next daily digest.'=>'%d zaidi wataiona kwenye muhtasari wao ujao wa kila siku.','%d new artwork published'=>'kazi %d mpya za sanaa zimechapishwa' . "\0" . 'kazi %d mpya za sanaa zimechapishwa','%d new event announced'=>'tukio %d jipya limetangazwa' . "\0" . 'matukio %d mapya yametangazwa','%d positive vote recorded so far.'=>'Kura chanya %d imerekodiwa hadi sasa.' . "\0" . 'Kura chanya %d zimerekodiwa hadi sasa.','%d positive vote(s) currently required for admission.'=>'%d kura chanya kwa sasa zinahitajika kwa ajili ya kukubaliwa.','%d vote to remove recorded so far.'=>'Kura %d ya kuondoa imerekodiwa hadi sasa.' . "\0" . 'Kura %d za kuondoa zimerekodiwa hadi sasa.','%dh ago'=>'saa %d zilizopita','%dm ago'=>'dakika %d zilizopita','%s (original)'=>'%s (asili)','%s (poster frame)'=>'%s (fremu ya bango)','%s already removed.'=>'%s tayari imeondolewa.','%s Newsletter'=>'Jarida la %s','%s — art blooming out of oblivion'=>'%s — sanaa ikichipuka kutoka kwenye usahaulifu','(deleted artist #%d)'=>'(msanii aliyefutwa #%d)','(no name provided)'=>'(hakuna jina lililotolewa)','.txt file(s) in the directory'=>'faili .txt katika saraka','[%1$s] Community message from %2$s'=>'[%1$s] Ujumbe wa jumuiya kutoka %2$s','[%1$s] New application received: %2$s'=>'[%1$s] Ombi jipya limepokelewa: %2$s','[%s] Community newsletter'=>'[%s] Jarida la jumuiya','[%s] Confirm your newsletter subscription'=>'[%s] Thibitisha usajili wako wa jarida','[%s] Newsletter'=>'[%s] Jarida','[%s] We couldn\'t find a photo in your email'=>'[%s] Hatukuweza kupata picha katika barua pepe yako','[%s] We couldn\'t find that artwork'=>'[%s] Hatukuweza kupata kazi hiyo ya sanaa','[%s] We couldn\'t find that artwork or event'=>'[%s] Hatukuweza kupata kazi hiyo ya sanaa au tukio hilo','[%s] We couldn\'t process that email'=>'[%s] Hatukuweza kuchakata barua pepe hiyo','[%s] We couldn\'t process your submission'=>'[%s] Hatukuweza kuchakata uwasilishaji wako','[%s] Your artwork is now featured'=>'[%s] Kazi yako ya sanaa sasa imeangaziwa','[%s] Your community message was not sent — no content found'=>'[%s] Ujumbe wako wa jumuiya haukutumwa — hakuna maudhui yaliyopatikana','[%s] Your community message was not sent — too long'=>'[%s] Ujumbe wako wa jumuiya haukutumwa — ni mrefu sana','[Agnosis] Confirm removal of: %s'=>'[Agnosis] Thibitisha uondoaji wa: %s','[Agnosis] Multiple items titled "%s" — choose which to remove'=>'[Agnosis] Vipengee vingi vinavyoitwa "%s" — chagua kimoja cha kuondoa','[Agnosis] Your submission is ready to review: %s'=>'[Agnosis] Uwasilishaji wako uko tayari kukaguliwa: %s','[Biography] — biography update'=>'[Wasifu] — sasisho la wasifu','[Event] — event announcement'=>'[Tukio] — tangazo la tukio','[message removed]'=>'[ujumbe umeondolewa]','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[Picha] — chapisha kama ilivyo, bila uboreshaji wa AI (mbadala kwa programu za barua pepe zisizo na majina ya To:)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[Safi] — chapisha kwa usahihi kama ilivyotumwa, bila AI hata kidogo (mbadala kwa programu za barua pepe zisizo na majina ya To:)','[TEST] %s'=>'[MAJARIBIO] %s','[TEST] Branding preview from %s'=>'[TEST] Onyesho la chapa kutoka %s','[TEST] Deliverability check from %s'=>'[JARIBIO] Ukaguzi wa uwasilishaji kutoka kwa %s','A community vote to change the membership size cap (proposal #%d) closed without a majority. The cap is unchanged.'=>'Kura ya jumuiya ya kubadilisha kikomo cha ukubwa wa uanachama (pendekezo #%d) ilifungwa bila kupata wengi. Kikomo hakijabadilika.','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'Hiki ni ukaguzi wa uchunguzi tu — hakuna kinachobadilisha namna barua zinavyotumwa. Katika huduma ya kawaida ya mwenyeji (PHP mail(), bila programu-jalizi ya SMTP), barua zinazotumwa kutoka kwa anwani isiyolingana na domeni ya tovuti yako, au kutoka kwa domeni isiyo na rekodi ya SPF/DMARC kabisa, zina uwezekano mkubwa zaidi wa kuingia kwenye taka au kukataliwa moja kwa moja na watoa huduma wakubwa wa visanduku vya barua. Ikiwa safu yoyote hapa chini inaonekana si sahihi, suluhisho la kuaminika zaidi ni kusakinisha programu-jalizi ya kutuma SMTP (WP Mail SMTP, Post SMTP, FluentSMTP, na nyinginezo zote hufanya kazi) iliyosanidiwa dhidi ya mtoa huduma halisi wa barua za miamala, na kuongeza rekodi za SPF/DMARC kwa domeni unayotuma kutoka kwake kwenye mwenyeji wako wa DNS.','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'Pendekezo tofauti la kikomo tayari linaendelea. Tatua au liunge mkono hilo kwanza.','A few sentences about your practice, medium, and background.'=>'Sentensi chache kuhusu mazoezi yako, mbinu, na historia.','A majority of active members (more than 50%) must vote yes for the removal to proceed. You can change your vote by clicking the other link before the deadline.'=>'Wingi wa wanachama hai (zaidi ya 50%) lazima wapige kura ya ndiyo ili uondoaji uendelee. Unaweza kubadilisha kura yako kwa kubofya kiungo kingine kabla ya muda wa mwisho.','A previous issue is still sending — please wait for it to finish.'=>'Toleo la awali bado linatumwa — tafadhali subiri likamilike.','A Privacy Policy page is set.'=>'Ukurasa wa Sera ya Faragha umewekwa.','A public key is required to register a peer.'=>'Funguo ya umma inahitajika ili kusajili rika.','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'Barua pepe, jina, wasifu, taarifa, na kiungo cha jalada cha ombi lililokataliwa, lililofutwa, au lililoondoka hufichwa jina na usafishaji wa kila siku baada ya siku hizi — rekodi ya ombi yenyewe (hali na tarehe) huhifadhiwa kwa historia ya uandikishaji. Wasifu/taarifa/jalada za msanii aliyepigwa marufuku hufichwa jina kwa ratiba hiyo hiyo, lakini barua pepe yao huhifadhiwa kimakusudi ili marufuku ibaki kutekelezeka. Chaguo msingi: siku 180.','A strict majority of active members (more than 50%) must vote yes for the new cap to be adopted. Sign in to your account to cast your vote.'=>'Wingi mkali wa wanachama hai (zaidi ya 50%) lazima wapige kura ya ndiyo ili kikomo kipya kikubaliwe. Ingia kwenye akaunti yako ili kupiga kura yako.','A valid removal token is required.'=>'Tokeni halali ya uondoaji inahitajika.','About %s'=>'Kuhusu %s','Absolute minimum positive votes required regardless of the percentage above.'=>'Idadi kamili ya chini ya kura chanya zinazohitajika bila kujali asilimia iliyo hapo juu.','Accent color'=>'Rangi ya lafudhi','Account not found.'=>'Akaunti haikupatikana.','Action'=>'Kitendo','Actions'=>'Vitendo','Active'=>'Hai','Actor document could not be fetched (cached failure).'=>'Actor document could not be fetched (cached failure).','Actor document does not contain a publicKey.publicKeyPem field.'=>'Hati ya mtendaji haina uga publicKey.publicKeyPem.','Actor document returned a non-200 response.'=>'Hati ya mtendaji ilirudisha jibu lisilo la 200.','Add New'=>'Ongeza Mpya','Add New Artwork'=>'Ongeza Kazi Mpya ya Sanaa','Add New Biography'=>'Ongeza Wasifu Mpya','Add New Event'=>'Ongeza Tukio Jipya','Add New Medium'=>'Ongeza Kati Mpya','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'Ongeza kizuizi cha "Usajili wa Jarida" kwenye ukurasa wowote ili kuwaruhusu wageni kujisajili kwa jarida la umma. Wasanii hujiandikisha kiotomatiki na wanaweza kujiondoa kutoka kwa toleo lolote kwa mbofyo mmoja.','Additional disallowed categories'=>'Kategoria nyingine zisizoruhusiwa','Address'=>'Anwani','Admin access required.'=>'Ufikiaji wa msimamizi unahitajika.','Admission minimum votes'=>'Idadi ya chini ya kura za kujiunga','Admission vote threshold (%)'=>'Kizingiti cha kura za kujiunga (%)','Admission vouch given'=>'Vouch ya uandikishaji iliyotolewa','Admit'=>'Kubali','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'Wasanii waliokubaliwa hujiandikishwa kiotomatiki (wanaweza kujitoa kutoka kwenye toleo lolote kwa kubofya mara moja). Muhtasari wa jumuiya: shughuli za hivi karibuni, wanachama wapya, kura zilizo wazi.','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'Ni onyo tu — kutuma kwa kujihostia kutaendelea kufanya kazi juu ya idadi hii. Mara tu idadi ya waliojisajili wa umma iliyothibitishwa inapopita hiki, ukurasa huu huonyesha kumbusho la kufikiria mtoa huduma wa barua pepe (kwa mfano, kiwango cha bure cha Brevo) badala yake.','After applying, send artists to'=>'Baada ya kuomba, tuma wasanii kwenda','Agnosis'=>'Agnosis','Agnosis Artist'=>'Msanii wa Agnosis','Agnosis Contact Messages Sent'=>'Ujumbe wa Mawasiliano wa Agnosis Uliotumwa','Agnosis Governance Participation'=>'Ushiriki katika Utawala wa Agnosis','Agnosis Inbox'=>'Sanduku la Ingizo la Agnosis','Agnosis is a federated art-publishing plugin. The following is a starting point for describing what it collects — review and adapt it to your site\'s actual configuration before publishing.'=>'Agnosis ni programu-jalizi ya uchapishaji wa sanaa iliyounganishwa kwa mtandao wa fediverse. Ifuatayo ni sehemu ya kuanzia ya kuelezea kile inachokusanya — kagua na urekebishe ili ilingane na usanidi halisi wa tovuti yako kabla ya kuchapisha.','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis ni nyumba ndogo inayojimiliki kwa wasanii ambao wangependelea kuunda kazi kuliko kusimamia jukwaa. Hakuna algoriti inayooamua nani anaona sanaa yako, hakuna tovuti ya jalada ya kutunza, na hakuna akaunti ya kusanidi — ni kazi yako tu, iliyochapishwa na kutafsiriwa kiotomatiki kwa hadhira ya kimataifa.

Kuwa sehemu ya jamii ni rahisi: Wasanii wenzako wanawaidhinisha waombaji wapya, na kila mtu hubaki na umiliki kamili wa kile anachochapisha; unaweza kuondoka wakati wowote na kuchukua kazi yako pamoja nawe.

Ukishaingizwa, unawasilisha kazi mpya kwa kuituma kama barua pepe — hakuna dashibodi, hakuna fomu na unaweza pia kusasisha, kutangaza au kuondoa kazi yako kwa kutuma barua pepe. Unaweza kupata taarifa zaidi kwa kutembelea tovuti ya agnosis.art.','Agnosis Membership Application'=>'Ombi la Uanachama wa Agnosis','Agnosis Newsletter Delivery History'=>'Historia ya Uwasilishaji wa Jarida la Agnosis','Agnosis Newsletter Subscription'=>'Usajili wa Jarida la Agnosis','Agnosis Notification Preferences'=>'Mapendeleo ya Arifa ya Agnosis','Agnosis requires PHP %s or higher.'=>'Agnosis inahitaji PHP %s au toleo jipya zaidi.','Agnosis requires WordPress %s or higher.'=>'Agnosis inahitaji WordPress %s au toleo jipya zaidi.','Agnosis Transactions'=>'Miamala ya Agnosis','Agnosis update blocked: download host "%s" is not on the allowlist.'=>'Uboreshaji wa Agnosis umezuiwa: seva pangishi ya upakuaji "%s" haipo kwenye orodha ya kuruhusiwa.','Agnosis update blocked: SHA-256 of the downloaded package does not match the manifest. The file may have been tampered with.'=>'Uboreshaji wa Agnosis umezuiwa: SHA-256 ya kifurushi kilichopakuliwa hailingani na manifesti. Huenda faili limechezewa.','Agnosis — Artist Subdomain Routing is disabled'=>'Agnosis — Uelekezaji wa Kikoa Kidogo cha Msanii umezimwa','AI Processing & Privacy Policy'=>'Sera ya Faragha ya Usindikaji wa AI','AI Providers'=>'Watoa Huduma wa AI','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'Majina ya istilahi za lebo/medium yaliyotafsiriwa na AI, yaliyoakibishwa ili istilahi ile ile ipate lebo ile ile iliyotafsiriwa kila mara badala ya kauli mpya ya AI kwa chapisho kila moja. Kubadilisha jina la istilahi tayari hufuta ingizo lake lililoakibishwa kiotomatiki; tumia kitufe kilicho hapa chini tu ikiwa tafsiri iliyohifadhiwa yenyewe si sahihi.','All'=>'Zote','All Artworks'=>'Kazi Zote za Sanaa','All Biographies'=>'Wasifu Zote','All Events'=>'Matukio Yote','All Mediums'=>'Vitu vyote vya kati','All reasons'=>'Sababu zote','All statuses'=>'Hali zote','Almost there — check your inbox for a confirmation email and click the link to open your application for community review.'=>'Tayari karibu — angalia kikasha chako kwa barua pepe ya uthibitisho na ubofye kiungo ili kufungua ombi lako kwa ukaguzi wa jumuiya.','Almost there — check your inbox for a confirmation link.'=>'Karibu — angalia kikasha chako kwa kiungo cha uthibitisho.','Amount'=>'Kiasi','An account with this email address already exists.'=>'Tayari kuna akaunti yenye anwani hii ya barua pepe.','An application for this email address is already pending.'=>'Tayari kuna ombi linalosubiri kwa anwani hii ya barua pepe.','An artist has left %s'=>'Msanii ameondoka %s','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'Huchambua picha ya kazi ya sanaa na kuandika kichwa, mwili, lebo na alt text. WordPress AI Services hupeleka kazi kwa mtoa huduma yeyote ambaye tovuti imesanidi kupitia programu-jalizi ya AI Services.','and switch the URL strategy to'=>'na ubadilishe mkakati wa URL kuwa','Announce an upcoming event.'=>'Tangazia tukio lijalo.','Anthropic'=>'Anthropic','Anthropic API key'=>'Ufunguo wa API wa Anthropic','Anthropic API key not configured.'=>'Ufunguo wa API wa Anthropic haujasanidiwa.','Anthropic connection successful.'=>'Muunganisho wa Anthropic umefanikiwa.','Anthropic model'=>'Muundo wa Anthropic','Anthropic text model'=>'Anthropic text model','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'Msanii yeyote aliye hai hutuma barua pepe hapa (somo lolote, hakuna kiambatisho kinachohitajika) kutuma ujumbe kwa kila mwanajumuiya mwingine — kwa mfano community@agnosis.art. Haichakatwi kamwe kama uwasilishaji na haigeuki kuwa chapisho: kila mpokeaji hupokea somo na ujumbe vikitafsiriwa katika lugha yake, pamoja na jina na barua pepe ya mtumaji ili aweze kujibu moja kwa moja. Hutumwa kutoka kwa anwani iliyosanidiwa chini ya Settings → Community → Rules, ambayo inaweza kuwa tofauti na hii. Hufanya kazi tu kwa ujumbe uliotumwa na msanii hai, aliyekubaliwa.','Any previously featured artwork has been unfeatured automatically — only one piece is featured at a time.'=>'Kazi yoyote ya sanaa iliyoangaziwa hapo awali imeondolewa kiotomatiki kwenye kuangaziwa — ni kipande kimoja tu kinachoweza kuangaziwa kwa wakati mmoja.','Applicant'=>'Mwombaji','Applicant admitted. A welcome email has been sent.'=>'Mwombaji amekubaliwa. Barua pepe ya kukaribisha imetumwa.','Application by %s has closed'=>'Ombi la %s limefungwa','Application confirmed'=>'Ombi limethibitishwa','application emailEmail: %s'=>'Barua pepe: %s','Application ID: %d'=>'Kitambulisho cha ombi: %d','Application not found.'=>'Ombi halikupatikana.','Application rejected.'=>'Ombi limekataliwa.','Application statement'=>'Taarifa ya ombi','Application vote emails'=>'Barua pepe za kura za maombi','Applied'=>'Aliomba','Applied at'=>'Ilituma ombi tarehe','Apply'=>'Omba','Apply to join'=>'Omba kujiunga','Art blooming out of oblivion'=>'Sanaa inayochipuka kutoka kwenye usahaulifu','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'Sanaa linalochipuka kutoka kwenye usahaulifu. Tuma sanaa yako kwa barua pepe, AI inaisafisha, ulimwengu unaiona. Mtandao huru wa uchapishaji uliofederishwa kwa wasanii huru.','Artist'=>'Msanii','Artist access required.'=>'Ufikivu wa msanii unahitajika.','Artist Contact Form'=>'Fomu ya Mawasiliano ya Msanii','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'Msanii hutuma barua pepe hapa (somo lolote, hakuna kiambatisho kinachohitajika) kuomba ufutaji wa akaunti. Kiungo cha uthibitisho hutumwa kwa barua pepe kabla ya chochote kufutwa — kwa mfano goodbye@agnosis.art','Artist Name'=>'Jina la Msanii','Artist newsletter'=>'Jarida la wasanii','Artist newsletter frequency (days)'=>'Marudio ya jarida la wasanii (siku)','Artist newsletter intro'=>'Utangulizi wa jarida la wasanii','Artist not found.'=>'Msanii hakupatikana.','Artist permanently deleted. Their account and all content have been removed.'=>'Msanii amefutwa kabisa. Akaunti yake na maudhui yote yameondolewa.','Artist prompt template'=>'Kiolezo cha amri ya msanii','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'Msanii huomba kazi ya sanaa iliyopo iondolewe. Somo lazima lilingane na kichwa. Hupeleka chapisho kuwa rasimu inayosubiri ukaguzi wa msimamizi — kwa mfano remove@agnosis.art','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'Msanii hutuma toleo jipya la kazi ya sanaa iliyopo. Somo lazima lilingane na kichwa cha asili. Hupita ugunduzi wa nakala — kwa mfano replace@agnosis.art','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'Msanii hutuma barua pepe hapa (somo = kichwa halisi cha kazi ya sanaa) ili kuchagua ni kazi gani inayowakilisha katika ghala la jamii linaloshirikiwa kwenye tovuti kuu — si subdomain yake mwenyewe, ambayo tayari inaonyesha kila kitu alichochapisha. Kazi yoyote ya sanaa iliyokuwa imeangaziwa hapo awali hushushwa kiotomatiki — kwa mfano promote@agnosis.art','Artist subdomain routing is'=>'Uelekezaji wa kikoa kidogo cha msanii','Artist suspended. A notification email has been sent.'=>'Msanii amesimamishwa. Barua pepe ya taarifa imetumwa.','artist@example.com'=>'artist@example.com','Artists are automatically subscribed — there is nothing to confirm.'=>'Wasanii husajiliwa kiotomatiki — hakuna cha kuthibitisha.','Artists send artwork to this address — e.g. submit@agnosis.art'=>'Wasanii hutuma sanaa kwenye anwani hii — kwa mfano submit@agnosis.art','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'Wasanii hutuma masasisho ya wasifu kwenye anwani hii — kwa mfano bio@agnosis.art','Artists send event announcements to this address — e.g. event@agnosis.art'=>'Wasanii hutuma matangazo ya matukio kwenye anwani hii — kwa mfano event@agnosis.art','Artwork'=>'Kazi ya sanaa','artwork'=>'kazi ya sanaa','Artwork (default) — any subject'=>'Kazi ya sanaa (chaguo-msingi) — somo lolote','Artwork Archives'=>'Nyaraka za Kazi ya Sanaa','Artwork Attributes'=>'Sifa za Kazi ya Sanaa','Artwork display width (px)'=>'Upana wa kuonyesha kazi ya sanaa (px)','Artwork or event not found.'=>'Kazi ya sanaa au tukio halikupatikana.','Artwork published'=>'Kazi ya sanaa imechapishwa','Artwork removed'=>'Kazi ya sanaa imeondolewa','Artwork submissions address'=>'Anwani ya uwasilishaji wa sanaa','Artworks'=>'Kazi za sanaa','Attachment viewer'=>'Kivinjari cha viambatisho','Audience'=>'Hadhira','Authentication required.'=>'Uthibitishaji unahitajika.','Auto (OpenAI if key is set)'=>'Kiotomatiki (OpenAI ikiwa ufunguo umewekwa)','Auto-draft newsletter intros'=>'Kujizalishia rasimu za utangulizi za jarida','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'Funguo ya umma ya RSA iliyozalishwa kiotomatiki kwa nodi hii. Shiriki hii na nodi nyingine shirikishi.','Automatic review found that page\'s content isn\'t allowed to be embedded on this site.'=>'Ukaguzi wa kiotomatiki umegundua kuwa maudhui ya ukurasa huo hayaruhusiwi kupachikwa kwenye tovuti hii.','Automatic review of that page\'s content was inconclusive.'=>'Ukaguzi wa kiotomatiki wa maudhui ya ukurasa huo haukuleta hitimisho la wazi.','Awaiting Review'=>'Inasubiri Uhakiki','Background color of the card itself — where the body text and footer sit. Keep this light for readable dark text below; for a dark theme, also darken the text colors.'=>'Rangi ya mandharinyuma ya kadi yenyewe — mahali ambapo maandishi ya mwili na kijachini hukaa. Iweke hii ikiwa nyepesi ili maandishi meusi yaweze kusomeka chini; kwa mandhari ya giza, pia fanya rangi za maandishi kuwa za giza.','Background color of the colored header bar on every outgoing HTML email.'=>'Rangi ya mandharinyuma ya upau wa kichwa wenye rangi kwenye kila barua pepe ya HTML inayoondoka.','Background color of the footer strip at the bottom of every outgoing HTML email (the tagline, and — on emails that have one — the work-addresses card and unsubscribe/preferences link). Independent of the card background above, so the footer can be set off visually from the body if you like.'=>'Rangi ya mandharinyuma ya utepe wa kijachini chini ya kila barua pepe ya HTML inayoondoka (kaulimbiu, na — kwenye barua pepe zilizo nayo — kadi ya anwani za kazi na kiungo cha kujiondoa/mapendeleo). Huru dhidi ya mandharinyuma ya kadi hapo juu, hivyo kijachini kinaweza kutengwa kwa mwonekano kutoka kwa mwili ukipenda.','Background color of the shaded info/quote boxes used throughout outgoing HTML email — quoted bios and statements, "did you mean" suggestions, application summaries, and similar callouts.'=>'Rangi ya mandharinyuma ya visanduku vya taarifa/nukuu vyenye kivuli vinavyotumika kote kwenye barua pepe ya HTML inayoondoka — wasifu na kauli zilizonukuliwa, mapendekezo ya "ulimaanisha", muhtasari wa maombi, na dondoo kama hizo.','Background color that surrounds the email card — the "letterbox" area visible in most desktop mail clients. Distinct from the card background below.'=>'Rangi ya mandharinyuma inayozunguka kadi ya barua pepe — eneo la "sanduku la barua" linaloonekana katika wateja wengi wa barua pepe wa eneo-kazi. Tofauti na mandharinyuma ya kadi iliyo hapa chini.','Banned'=>'Amefungiwa','Banned until %s'=>'Amefungiwa hadi %s','Base domain'=>'Kikoa cha msingi','Baseline (default)'=>'Msingi (chaguo-msingi)','Behavior'=>'Tabia','Bell'=>'Kengele','Bio'=>'Bayo','Bio / Portfolio'=>'Wasifu / Portfolio','Biographies'=>'Wasifu','Biography'=>'Wasifu','biography'=>'wasifu','Biography Icon'=>'Ikoni ya wasifu','Biography icon'=>'Ikoni ya wasifu','Biography published'=>'Wasifu umechapishwa','Biography removed'=>'Wasifu umeondolewa','Biography submissions address'=>'Anwani ya uwasilishaji wa wasifu','block descriptionA single icon-only link (Biography, Events, or a Contact popover) to/about the current artist. Renders nothing if there\'s nothing to show (no biography/events yet, or the artist has turned contact off), or off an artist subdomain.'=>'Kiungo kimoja chenye ikoni pekee (Wasifu, Matukio, au popo ya Mawasiliano) kwa/kuhusu msanii wa sasa. Hauchapi chochote ikiwa hakuna cha kuonyesha (bado hakuna wasifu/matukio, au msanii amezima mawasiliano), au nje ya subdomain ya msanii.','block descriptionContact form letting a visitor message the current artist subdomain\'s artist. Submits to a per-artist REST endpoint; the message is moderated, translated into the artist\'s own language, and emailed to them.'=>'Fomu ya mawasiliano inayomruhusu mgeni kumtumia ujumbe msanii wa subdomain ya sasa ya msanii. Hutumwa kwenye mwisho wa REST wa kila msanii; ujumbe huchujwa, kutafsiriwa katika lugha ya msanii mwenyewe, na kutumwa kwake kwa barua pepe.','block descriptionEmail signup form for the public newsletter (double opt-in). Submits to the newsletter subscribe REST endpoint.'=>'Fomu ya kujisajili kwa barua pepe kwa jarida la umma (uthibitishaji wa hatua mbili). Hutumwa kwenye mwisho wa REST wa kujisajili kwenye jarida.','block descriptionIcon button that opens a full-viewport popover containing the newsletter signup form. Self-contained — drop it directly into a header or footer template part; renders nothing when the public newsletter is disabled (Settings → Newsletter).'=>'Kitufe cha ikoni kinachofungua popo la ukurasa mzima lenye fomu ya kujisajili kwa jarida. Kinafanya kazi kivyake — kiweke moja kwa moja kwenye sehemu ya kichwa au kiolezo cha sehemu ya chini; hakinachi chochote jarida la umma likiwa limezimwa (Mipangilio → Jarida).','block descriptionLinks to the current artist\'s own subdomain home. Renders nothing off an artist subdomain.'=>'Huunganisha kwenye ukurasa wa nyumbani wa subdomain ya msanii wa sasa. Hauchapi chochote nje ya subdomain ya msanii.','block descriptionLists the logged-in artist\'s pending artwork submissions for review and approval. Place this on your /my-submissions/ page or in a Site Editor template.'=>'Huorodhesha mawasilisho ya kazi za sanaa yanayosubiri ya msanii aliyeingia kwa ajili ya mapitio na idhini. Weka hili kwenye ukurasa wako wa /my-submissions/ au kwenye kiolezo cha Site Editor.','block descriptionProportional, randomized artwork grid across all artists. Shows featured artworks first, respects per-artist budget, supports medium filtering and pagination.'=>'Gridi ya kazi za sanaa iliyopangwa kwa uwiano na nasibu kati ya wasanii wote. Huonyesha kazi zilizochaguliwa kwanza, huheshimu bajeti kwa kila msanii, huunga mkono uchujaji wa vyombo na upaganishaji wa kurasa.','block descriptionPublic application form for artists who want to join the Agnosis network. Submits to the admission REST endpoint. Place this on your /join/ page.'=>'Fomu ya maombi ya umma kwa wasanii wanaotaka kujiunga na mtandao wa Agnosis. Hutumwa kwenye mwisho wa REST wa uandikishaji. Weka hili kwenye ukurasa wako wa /join/.','block descriptionSmall line identifying the artist whose subdomain is currently being viewed. Renders nothing on the main Agnosis site.'=>'Mstari mfupi unaomtambulisha msanii ambaye subdomain yake inatazamwa kwa sasa. Hauchapi chochote kwenye tovuti kuu ya Agnosis.','Block gambling / betting sites'=>'Zuia tovuti za kamari / kubet','block keywordadmission'=>'uandikishaji','block keywordagnosis'=>'agnosis','block keywordapplication'=>'maombi','block keywordapply'=>'omba','block keywordartist'=>'msanii','block keywordartists'=>'wasanii','block keywordartwork'=>'kazi ya sanaa','block keywordbiography'=>'wasifu','block keywordbreadcrumb'=>'kipande cha mkate','block keywordcontact'=>'mawasiliano','block keywordemail'=>'barua pepe','block keywordevents'=>'matukio','block keywordfooter'=>'sehemu ya chini','block keywordgallery'=>'ghala','block keywordicon'=>'ikoni','block keywordjoin'=>'jiunge','block keywordmessage'=>'ujumbe','block keywordnewsletter'=>'jarida','block keywordoverview'=>'muhtasari','block keywordpopover'=>'popo','block keywordreview'=>'mapitio','block keywordsignup'=>'usajili','block keywordsubdomain'=>'subdomain','block keywordsubmissions'=>'mawasilisho','block keywordsubscribe'=>'jisajili','Block pornographic / sexually explicit content'=>'Zuia maudhui ya ponografia / ya wazi kingono','Block primarily commercial / promotional sites'=>'Zuia tovuti hasa za kibiashara / za matangazo','block titleAgnosis Gallery Overview'=>'Muhtasari wa Ghala la Agnosis','block titleArtist Breadcrumb'=>'Kipande cha mkate cha Msanii','block titleArtist Contact Form'=>'Fomu ya Mawasiliano ya Msanii','block titleArtist Name Link'=>'Kiungo cha Jina la Msanii','block titleBreadcrumb Icon Link'=>'Kiungo cha Ikoni ya Kipande cha Mkate','block titleJoin Agnosis'=>'Jiunge na Agnosis','block titleMy Submissions'=>'Mawasilisho Yangu','block titleNewsletter Popover'=>'Popo la Jarida','block titleNewsletter Signup'=>'Usajili wa Jarida','Book'=>'Kitabu','Bot Protection'=>'Ulinzi dhidi ya roboti','Bottom'=>'Chini','Bounce'=>'Kurudishwa','Bounced (too long)'=>'Imerudishwa (ndefu sana)','Branding'=>'Utambulisho wa chapa','Branding preview'=>'Onyesho la chapa','Branding preview sent — check the inbox you sent it to.'=>'Onyesho la chapa limetumwa — angalia kikasha ulichotumia kulituma.','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'Tangaza kazi mpya za sanaa kwa Mastodon, Pixelfed na Fediverse.','Broadcast Sent'=>'Matangazo Yametumwa','Button text color'=>'Rangi ya maandishi ya kitufe','By language: %s'=>'Kwa lugha: %s','Cached translations'=>'Tafsiri zilizoakibishwa','Calendar'=>'Kalenda','Camera shake is visible. Use a tripod or rest the camera on a flat surface and use the self-timer to avoid movement when pressing the shutter.'=>'Mtikisiko wa kamera unaonekana. Tumia tripod au weka kamera juu ya uso tambarare na tumia kipima muda cha kujipiga ili kuepuka kusogea unapobonyeza shutter.','Cancel'=>'Ghairi','Cap-change co-signers required'=>'Washirika wa kusaini kwa pamoja wa mabadiliko ya kikomo wanaohitajika','Cap-change vote window (days)'=>'Dirisha la kura la mabadiliko ya kikomo (siku)','Card background color'=>'Rangi ya mandharinyuma ya kadi','Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'Hukagua kwamba wp_ai_client_prompt() inapatikana (WordPress 7.0+) na modeli ya kutengeneza maandishi imesanidiwa.','Choose which artwork represents you in the shared community gallery on the main site — subject must match its title. Your own subdomain already shows everything you\'ve published.'=>'Chagua kazi gani ya sanaa inakuwakilisha kwenye galeria ya pamoja ya jamii kwenye tovuti kuu — somo lazima lilingane na kichwa chake. Kikoa chako kidogo tayari kinaonyesha kila kitu ulichochapisha.','Clear All'=>'Futa Yote','Clear all log entries?'=>'Futa maingizo yote ya kumbukumbu?','Clear Debug Files'=>'Futa Faili za Uchunguzi','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'Futa kila tafsiri ya istilahi iliyoakibishwa? Hakuna kinachofutwa kutoka kwenye tovuti yako — istilahi zitatafsiriwa tena na AI mara tu zitakapohitajika tena.','Clear Term Translation Cache'=>'Futa Akiba ya Tafsiri za Istilahi','Close'=>'Funga','Cloudflare Turnstile secret key'=>'Ufunguo wa siri wa Cloudflare Turnstile','Cloudflare Turnstile site key'=>'Ufunguo wa tovuti wa Cloudflare Turnstile','Color for muted/secondary text — the footer tagline, work-address descriptions, and small helper links (unsubscribe, notification preferences, "view online"). Matches the plugin\'s original hardcoded footer color, kept as the default.'=>'Rangi ya maandishi ya hali ya chini/ya pili — kaulimbiu ya kijachini, maelezo ya anwani za kazi, na viungo vidogo vya msaada (kujiondoa, mapendeleo ya arifa, "tazama mtandaoni"). Inalingana na rangi ya kijachini ya awali iliyowekwa kwa msimbo wa programu-jalizi, na imehifadhiwa kama chaguomsingi.','Color of primary buttons and links across every outgoing HTML email. Destructive actions (reject, remove, vote to remove) always use a fixed red regardless of this setting, so they stay visually distinct.'=>'Rangi ya vitufe na viungo vya msingi kwenye kila barua pepe ya HTML inayoondoka. Vitendo vya kuharibu (kukataa, kuondoa, kupiga kura ya kuondoa) daima hutumia nyekundu iliyowekwa bila kubadilika bila kujali mpangilio huu, ili viendelee kutofautishwa kwa mwonekano.','Color of the bold address labels ("Artwork:", "Biography:", etc.) in the work-addresses reference card that appears in the footer of artist-facing notification emails.'=>'Rangi ya lebo nzito za anwani ("Kazi ya sanaa:", "Wasifu:", n.k.) kwenye kadi ya marejeleo ya anwani za kazi inayoonekana kwenye kijachini cha barua pepe za arifa kwa wasanii.','Color of thin divider lines across outgoing HTML email — between the body and footer, above the work-addresses card, and around the newsletter\'s "view online" banner.'=>'Rangi ya mistari myembamba ya kutenganisha kwenye barua pepe ya HTML inayoondoka — kati ya mwili na kijachini, juu ya kadi ya anwani za kazi, na kuzunguka bango la jarida la "tazama mtandaoni".','Columns'=>'Safu wima','columns · proportional · random daily order'=>'safu wima · sawia · mpangilio wa nasibu wa kila siku','Commerce'=>'Biashara','Community'=>'Jamii','Community announcement address'=>'Anwani ya tangazo la jumuiya','Community broadcast max length (characters)'=>'Urefu wa juu wa matangazo ya jamii (herufi)','Community broadcasts are now muted.'=>'Matangazo ya jumuiya sasa yamenyamazishwa.','Community broadcasts per artist per day'=>'Matangazo ya jamii kwa kila msanii kwa siku','Community Newsletter'=>'Jarida la jumuiya','Community removal vote'=>'Kura ya kuondoa mwanajamii','Community removal vote did not pass at %s'=>'Kura ya kuondoa mwanachama haikupitishwa katika %s','Community removal vote open at %s'=>'Kura ya kuondoa mwanachama imefunguliwa katika %s','Community removal vote opened. All artists have been emailed.'=>'Kura ya kuondoa kwenye jamii imefunguliwa. Wasanii wote wamepokea barua pepe.','Community removal vote passed at %s'=>'Kura ya kuondoa mwanachama imepitishwa katika %s','Community size cap'=>'Kikomo cha ukubwa wa jamii','Community size cap changed at %s'=>'Kikomo cha ukubwa wa jumuiya kimebadilishwa katika %s','Community size-cap proposal did not pass at %s'=>'Pendekezo la kikomo cha ukubwa wa jumuiya halikupita katika %s','Community size-cap vote'=>'Kura ya kikomo cha ukubwa wa jamii','Community size-cap vote open at %s'=>'Kura ya kikomo cha ukubwa wa jumuiya imefunguliwa katika %s','Community vouch given'=>'Vouch ya jamii iliyotolewa','completely inactive'=>'haupo kabisa','Configuration'=>'Mipangilio','Confirm my application'=>'Thibitisha ombi langu','Confirm my vote'=>'Thibitisha kura yangu','Confirm removal'=>'Thibitisha uondoaji','Confirm subscription'=>'Thibitisha usajili','Confirm unsubscribe'=>'Thibitisha kujiondoa','Confirm your application to %s'=>'Thibitisha ombi lako kwa %s','Confirm your application?'=>'Thibitisha ombi lako?','Confirm your departure from %s'=>'Thibitisha kuondoka kwako kutoka %s','Confirm your subscription?'=>'Ungependa kuthibitisha usajili wako?','Confirmed at'=>'Imethibitishwa tarehe','Connected successfully. %1$d message(s) in inbox, %2$d unseen.'=>'Umeunganishwa kwa mafanikio. Kuna ujumbe %1$d kwenye kikasha, %2$d haujaonekana.','Connects to the configured mailbox and reports the total and unseen message count.'=>'Huunganishwa na kisanduku cha barua kilichosanidiwa na kuripoti jumla ya ujumbe na idadi ya ujumbe ambao haujasomwa.','Contact'=>'Mawasiliano','Contact %s'=>'Wasiliana na %s','contact form reply-to emailEmail: %s'=>'Barua pepe: %s','Contact Icon'=>'Ikoni ya mawasiliano','Contact message retention (days)'=>'Uhifadhi wa ujumbe wa mawasiliano (siku)','Contact Messages'=>'Ujumbe wa Mawasiliano','Contact this artist'=>'Wasiliana na msanii huyu','Content not found.'=>'Maudhui hayakupatikana.','Context'=>'Muktadha','Could not admit — the application may no longer be pending.'=>'Haikuwezekana kumkubali — huenda ombi haliko tena katika hali ya kusubiri.','Could not connect. Please try again.'=>'Haikuweza kuunganishwa. Tafadhali jaribu tena.','Could not delete the artist — please try again.'=>'Haikuwezekana kumfuta msanii — tafadhali jaribu tena.','Could not open a removal vote — one may already be active for this artist.'=>'Haikuwezekana kufungua kura ya kuondoa — huenda tayari kuna moja inayofanya kazi kwa msanii huyu.','Could not reject — the application may no longer be pending.'=>'Haikuwezekana kukataa — huenda ombi haliko tena katika hali ya kusubiri.','Could not remove the %s. Please try again.'=>'Haikuwezekana kuondoa %s. Tafadhali jaribu tena.','Could not send the branding preview — check the address and your site\'s outgoing mail configuration.'=>'Haikuweza kutuma onyesho la chapa — angalia anwani na usanidi wa barua pepe inayoondoka wa tovuti yako.','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'Haikuweza kutuma mwaliko — angalia anwani na usanidi wa barua zinazotoka wa tovuti yako.','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'Haikuweza kutuma barua pepe ya majaribio — angalia anwani na usanidi wa barua zinazotoka wa tovuti yako.','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'Haikuweza kutuma mwaliko wa majaribio — angalia anwani na usanidi wa barua zinazotoka wa tovuti yako.','Could not start this issue — a previous one may still be sending.'=>'Haikuweza kuanzisha toleo hili — huenda kuna jingine lililopita bado linatumwa.','Could not suspend the artist — they may no longer be active.'=>'Haikuwezekana kumsimamisha msanii — huenda si hai tena.','Could not verify you\'re human right now. Please try again in a moment.'=>'Tungeweza kuthibitisha sasa hivi kuwa wewe ni binadamu. Tafadhali jaribu tena baada ya muda mfupi.','Currency'=>'Sarafu','Currently'=>'Kwa sasa','Date'=>'Tarehe','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'Siku ambazo kura ya mabadiliko ya kikomo cha jamii hubaki wazi. Wingi thabiti wa zaidi ya nusu ya wasanii hai wanaopiga kura ya ndiyo hupitisha kikomo kipya.','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'Siku ambazo kura ya jamii ya kuondoa hubaki wazi. Wingi wa zaidi ya 50% ya wasanii hai lazima wapige kura ya ndiyo ili kuondoa kuendelee.','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'Siku ambazo ombi hubaki wazi. Ikiwa kizingiti hakijafikiwa ndani ya dirisha hili ombi linakataliwa.','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'Dampo za utatuzi zilizozeeka kuliko siku hizi hufutwa kabisa na usafishaji wa kila siku — kiotomatiki, iwe uwekaji wa kumbukumbu za utatuzi umewashwa kwa sasa au la, ili faili zilizosalia kutoka kikao cha awali cha utatuzi zisionekane milele. Dampo ni nakala ghafi kamili ya barua pepe ya msanii, kwa hiyo chaguo-msingi ni muda mfupi kuliko uhifadhi wa kisanduku pokezi/foleni hapo juu. Chaguo-msingi: siku 14.','Debug file retention (days)'=>'Uhifadhi wa faili za utatuzi (siku)','Debug Files'=>'Faili za Uchunguzi','Debug files cleared. %d file was removed.'=>'Faili za utatuzi zimefutwa. Faili %d imeondolewa.' . "\0" . 'Faili za utatuzi zimefutwa. Faili %d zimeondolewa.','Debug logging'=>'Uwekaji wa kumbukumbu za utatuzi','Dedicated From: address for admission, vote, welcome, departure, invitation, and submission-review emails — e.g. hello@agnosis.art. This is not one of the endpoint addresses below (submit@, bio@, community@, etc.) — those are where artists send mail in; this is who workflow mail appears to come from. Separate from the Settings → Newsletter sender, which only covers digest mail. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Anwani maalum ya From: kwa barua pepe za uandikishaji, kura, makaribisho, kuondoka, mwaliko, na ukaguzi wa uwasilishaji — kwa mfano hello@agnosis.art. Hii si mojawapo ya anwani za mwisho zilizo hapa chini (submit@, bio@, community@, n.k.) — hizo ni mahali ambapo wasanii hutuma barua pepe; hii ndiyo barua pepe ambayo maili ya mtiririko wa kazi huonekana kutoka. Imetofautiana na Settings → Sender wa Jarida, ambao unahusu tu barua pepe za muhtasari wa kila siku. Acha tupu kutumia barua pepe ya msimamizi. Lazima iwe anwani halali inayoweza kupokelewa kwenye kikoa chako (SPF/DKIM zimewekwa) au ujumbe unaweza kuainishwa kama taka.','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'Anwani ya From: mahususi kwa barua pepe zote mbili, kwa mfano newsletter@agnosis.art — hutenganisha barua za muhtasari na barua pepe ya admin ya tovuti kwa ajili ya uwasilishaji, na ili wasanii waweze kuichuja. Acha tupu ili kutumia barua pepe ya admin. Lazima iwe anwani halali, inayoweza kupokelewa kwenye domeni yako (SPF/DKIM imesanidiwa) la sivyo ujumbe unaweza kuwekwa kama barua taka.','Default 30 ≈ monthly.'=>'Chaguo-msingi 30 ≈ kila mwezi.','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'Chaguo msingi 30 ≈ kila mwezi. Toleo jipya huandaliwa mara tu siku hizi nyingi zinapopita tangu la mwisho kutumwa.','Default base font size for body text. Default: 16.'=>'Ukubwa chaguomsingi wa msingi wa fonti kwa maandishi ya mwili. Chaguomsingi: 16.','Default color for body text — the main reading text of every outgoing HTML email.'=>'Rangi chaguomsingi ya maandishi ya mwili — maandishi makuu ya kusoma ya kila barua pepe ya HTML inayoondoka.','Delete'=>'Futa','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'Futa faili zote .txt katika saraka ya uchunguzi? Saraka yenyewe itabaki mahali pake ili uandishi wa uchunguzi wa baadaye bado uweze kutua vizuri.','Delete this message?'=>'Ufute ujumbe huu?','Delete this queue row?'=>'Ufuta safu hii ya foleni?','Deliverability'=>'Uwasilishaji','Description'=>'Maelezo','Description provider'=>'Mtoa huduma wa maelezo','Detected: %s'=>'Imegunduliwa: %s','Did you mean "%s"?'=>'Ulimaanisha "%s"?','Didn\'t look right? Adjust the fields above and send another test — nothing here was recorded or sent to anyone but you.'=>'Haikuonekana sawa? Rekebisha sehemu zilizo hapo juu na utume jaribio jingine — hakuna kilichorekodiwa hapa wala kutumwa kwa mtu yeyote isipokuwa wewe.','Digest header does not match the request body.'=>'Kichwa cha digest hakilingani na mwili wa ombi.','Directory'=>'Saraka','Disabled'=>'Imezimwa','Disabled — use original image'=>'Imelemazwa — tumia picha ya asili','Discard'=>'Tupa','Discard this submission?'=>'Utupilie mbali uwasilishaji huu?','Discard this submission? This cannot be undone.'=>'Utupilie mbali uwasilishaji huu? Hili haliwezi kutenguliwa.','Discarded.'=>'Imeondolewa.','Discarding…'=>'Inaondolewa…','Display name'=>'Jina la kuonyesha','Display name: %s'=>'Jina la kuonyesha: %s','Divider / border color'=>'Rangi ya kigawanya / mpaka','DMARC record'=>'Rekodi ya DMARC','DNS lookup failed'=>'Utafutaji wa DNS umeshindwa','Domain matches site?'=>'Domeni inalingana na tovuti?','Double-check the link is correct — you can fix or remove it in the form below before publishing.'=>'Angalia tena kama kiungo ni sahihi — unaweza kukirekebisha au kukiondoa katika fomu iliyo hapa chini kabla ya kuchapisha.','Draft intro this many hours ahead'=>'Tengeneza rasimu ya utangulizi saa hizi ngapi kabla','e.g. imap.yourhost.com'=>'mf. imap.yourhost.com','Edit Artwork'=>'Hariri Kazi ya Sanaa','Edit Biography'=>'Hariri Wasifu','Edit Event'=>'Hariri Tukio','Edit Medium'=>'Hariri Kati','Email address'=>'Anwani ya barua pepe','Email driver'=>'Kiendeshi cha barua pepe','Email image width (px)'=>'Upana wa picha ya barua pepe (px)','Email Inbox'=>'Kisanduku Pokezi cha Barua Pepe','Email logo'=>'Nembo ya barua pepe','Email signup form for the public newsletter. A confirmation email is sent before anyone is added to the send list (double opt-in). Content is rendered live on the frontend.'=>'Fomu ya kujisajili kwa barua pepe kwa jarida la umma. Barua pepe ya uthibitisho hutumwa kabla ya mtu yeyote kuongezwa kwenye orodha ya kutuma (uthibitishaji wa hatua mbili). Maudhui huonyeshwa moja kwa moja kwenye upande wa mbele.','Email width (px)'=>'Upana wa barua pepe (px)','Enable ActivityPub federation'=>'Wezesha muungano wa ActivityPub','Enabled'=>'Imewashwa','Endpoint'=>'Mwisho wa kusambazia','Enhancement instructions'=>'Maelekezo ya uboreshaji','Enhancement provider'=>'Mtoa huduma wa uboreshaji','Enhancement threshold (quality score)'=>'Kizingiti cha uboreshaji (alama ya ubora)','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'Huboresha picha ya kazi ya sanaa kabla ya kuchapishwa. Hutumia OpenAI gpt-image-1. Weka kuwa Imelemazwa ili kuruka uboreshaji na kuchapisha asili.','Enlarge'=>'Panua','Enlarged image'=>'Picha iliyopanuliwa','Envelope'=>'Bahasha','Error'=>'Hitilafu','Event'=>'Tukio','event'=>'tukio','Event published'=>'Tukio limechapishwa','Event removed'=>'Tukio limeondolewa','Event submissions address'=>'Anwani ya uwasilishaji wa matukio','Events'=>'Matukio','Events Icon'=>'Ikoni ya matukio','Events icon'=>'Ikoni ya matukio','Every 5 minutes'=>'Kila dakika 5','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'Kila msanii hapa tayari ameshathibitishwa na jamii — ikiwa uaminifu huo unakutosha, washa hili ili kupachika kiungo chochote msanii anachowasilisha, mara moja, bila ukaguzi wa orodha iliyoruhusiwa na bila ukaguzi wowote wa AI (mipangilio iliyo hapa chini hurukwa kabisa huku hiki kikiwasha). Huzima kwa chaguo-msingi. Washa hili tu ikiwa unaridhika kwamba mtu mbaya aliyefanikiwa kupita kwenye uandikishaji anaweza kupachika kiungo chochote.','Every recipient\'s copy is translated individually into their own language, so a very long message is costly to translate for the whole community. Please shorten it and send it again.'=>'Nakala ya kila mpokeaji hutafsiriwa kivyake katika lugha yake mwenyewe, kwa hivyo ujumbe mrefu sana ni wa gharama kutafsiri kwa jumuiya nzima. Tafadhali uufupishe na utume tena.','Excerpt word limit'=>'Kikomo cha maneno ya dondoo','Failed'=>'Imeshindikana','Failed recipients'=>'Wapokeaji walioshindwa','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'Wapokeaji walioshindwa wamewekwa tena kuwa inasubiri — watajaribiwa tena katika mizunguko michache ijayo ya cron.','Failed to fetch actor document.'=>'Imeshindikana kuchukua hati ya mtendaji.','Failed to insert attachment.'=>'Imeshindwa kuingiza kiambatisho.','Feature artwork in the shared gallery (subject: exact title)'=>'Onyesha kazi ya sanaa kwenye ghala la pamoja (somo: kichwa halisi)','Feature this artwork in the gallery overview'=>'Onyesha kazi hii ya sanaa kwenye muhtasari wa ghala','Featured'=>'Zilizoangaziwa','Featured artworks are always chosen first when selecting one work per artist for the homepage overview.'=>'Kazi za sanaa zilizoangaziwa huchaguliwa kila mara kwanza wakati wa kuchagua kazi moja kwa kila msanii kwa muhtasari wa ukurasa wa mwanzo.','Federated posts under this medium will carry a content warning on the Fediverse (e.g. Mastodon) unless the artist turns it off for a specific piece.'=>'Federated posts under this medium will carry a content warning on the Fediverse (e.g. Mastodon) unless the artist turns it off for a specific piece.','Fee'=>'Ada','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'Huchukua ujumbe ambao haujasomwa mara moja bila kusubiri WP-Cron. Kisha bofya "Chakata Foleni Zinazosubiri" ili kuendesha mlolongo wa AI.','Files'=>'Faili','Fill the frame — let the artwork take up most of the shot; crop out distracting backgrounds.'=>'Jaza fremu — acha kazi ya sanaa ichukue sehemu kubwa ya picha; kata mandharinyuma yanayokengeusha.','Filter'=>'Chuja','Filter by medium'=>'Chuja kwa aina ya kazi','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'Chuja kwa agnosis_debug_dir ili kuelekeza matokeo ya uchunguzi mahali pengine.','Fix: open'=>'Suluhisho: fungua','Flagged by automatic content review.'=>'Imebainishwa na ukaguzi wa maudhui wa kiotomatiki.','Font size for muted/secondary text — the footer tagline and smaller helper text below the main body copy. Default: 14.'=>'Ukubwa wa fonti kwa maandishi ya hali ya chini/ya pili — kaulimbiu ya kijachini na maandishi madogo ya msaada chini ya maandishi makuu ya mwili. Chaguomsingi: 14.','Footer background color'=>'Rangi ya mandharinyuma ya kijachini','Footer label color'=>'Rangi ya lebo ya kijachini','Force Reprocess'=>'Lazimisha Uchakataji Upya','Force reprocess'=>'Lazimisha kuchakata tena','Force Reprocess Inbox'=>'Lazimisha Kuchakata Tena Kisanduku Pokezi','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'Lazimisha uchakataji upya umekamilika. Safu %1$d za foleni zimewekwa upya, ujumbe mpya %2$d umeongezwa kwenye foleni. Bofya "Chakata Foleni Inayosubiri" ili kuendesha bomba la AI.','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'Lazimisha uchakataji upya: safu %1$d zimewekwa upya, ujumbe mpya %2$d umeongezwa kwenye foleni.','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'IMELAZIMISHWA KUWA ZIMWA na kigezo AGNOSIS_DEBUG katika wp-config.php — kisanduku cha tiki kilicho juu hakina athari hadi mstari huo uondolewe.','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'IMELAZIMISHWA KUWA WASHWA na kigezo AGNOSIS_DEBUG katika wp-config.php — kisanduku cha tiki kilicho juu hakina athari hadi mstari huo uondolewe.','Forgot your password?'=>'Umesahau nenosiri lako?','Found'=>'Imepatikana','From'=>'Kutoka','From identity'=>'Utambulisho wa kutoka','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'Kutoka kwenye kijipicha chako cha Cloudflare Turnstile (dash.cloudflare.com → Turnstile). Huongeza ukaguzi wa kuthibitisha binadamu kwenye fomu za umma za Subscribe (usajili wa jarida) na Join. Acha ufunguo wowote wazi ili kuacha fomu zote mbili zikiwa sawa kabisa kama zilivyo sasa.','From: %s'=>'Kutoka: %s','Full text'=>'Maandishi kamili','Gallery overview'=>'Muhtasari wa ghala','Gallery overview — items per page'=>'Muhtasari wa ghala — vipengee kwa kila ukurasa','Gallery pages'=>'Kurasa za ghala','Gallery settings'=>'Mipangilio ya ghala','Gateway'=>'Njia ya malipo','General'=>'Jumla','Get in touch'=>'Wasiliana nasi','Get in touch with %s'=>'Wasiliana na %s','Get new artworks, artist admissions, and community updates in your inbox.'=>'Pata kazi mpya za sanaa, uandikishaji wa wasanii, na masasisho ya jumuiya kwenye kikasha chako.','Give it a plain subject line — not one starting with "Re:" or containing "[Agnosis]".'=>'Weka kichwa rahisi — kisichoanza na "Re:" au chenye "[Agnosis]".','Go to Settings → Privacy'=>'Nenda kwenye Mipangilio → Faragha','Goodbye'=>'Kwaheri','Goodbye / self-removal address'=>'Anwani ya kwaheri / kujiondoa mwenyewe','Handled'=>'Imeshughulikiwa','Having trouble viewing this email?'=>'Unapata ugumu kuona barua pepe hii?','Header background'=>'Mandharinyuma ya kichwa','Helps us communicate and translate content in your language.'=>'Hutusaidia kuwasiliana na kutafsiri maudhui katika lugha yako.','Here\'s what our AI detected and how to fix it:'=>'Haya ndiyo AI yetu iligundua na jinsi ya kuyarekebisha:','Here\'s your daily digest of applications to %1$s still awaiting your vote. Each has a %2$d-day voting window from when it was confirmed.'=>'Huu hapa muhtasari wako wa kila siku wa maombi kwa %1$s ambayo bado yanasubiri kura yako. Kila moja lina dirisha la kupiga kura la siku %2$d kuanzia lilipothibitishwa.','Hi %s,'=>'Habari %s,','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'Bofya jibu ili kujibu — jibu lako litarudi kwa jumuiya nzima, likitafsiriwa kiotomatiki, kama ujumbe huu.','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'Siri ya HMAC inayoshirikiwa na mtoa huduma wako wa webhook (Mailgun, SendGrid…). Inatumika kwa endpoint ya barua zinazoingia (/wp-json/agnosis/v1/email/inbound) na pia endpoint ya matukio ya bounce/complaint (/wp-json/agnosis/v1/email/events) — elekeza webhook ya bounce/spam-complaint ya mtoa huduma wako kwenye ya mwisho ili kuweka anwani za wasajili na wasanii safi.','Hold still — tap the artwork on your screen to focus, then press the shutter gently or use a self-timer.'=>'Shikilia bila kusogea — gusa kazi ya sanaa kwenye skrini yako ili kufocus, kisha bonyeza shutter kwa upole au tumia kipima muda cha kujipiga.','Hour'=>'Saa','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'Ni muda gani kabla ya toleo Agnosis inapopendekeza utangulizi uliorasibiwa kwa AI. Hufanya kazi tu wakati kujizalishia rasimu kiotomatiki (hapo juu) kimewezeshwa. Chaguo msingi: 24.','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'Muda ambao viungo vya Approve & Publish / Discard katika barua pepe ya ukaguzi wa uwasilishaji hubaki halali kabla ya msanii kuhitaji kuingia ili kusimamia kipengee badala yake. Hutumika kwa usawa kwa rasimu za kazi ya sanaa, wasifu, na matukio. Chaguo-msingi: 7.','How long we retain your data'=>'Tunahifadhi data yako kwa muda gani','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'Ni wasanii wangapi lazima wasaini pamoja pendekezo la kubadilisha kikomo cha ukubwa wa jamii kabla halijafunguliwa kama kura kamili ya jamii.','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'Ni kadi ngapi za kazi za sanaa ambazo muhtasari wa ghala unaonyesha kwa kila ukurasa. Kundi hujengwa kwa uwiano katika wasanii wote; kazi za sanaa zilizoangaziwa hupendelewa. Chaguo-msingi: 12.','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'AI inapaswa kutengeneza tagi ngapi kwa kila kazi ya sanaa. Inatajwa kama {tag_count} katika amri ya mfumo.','How this node introduces itself to the network.'=>'Jinsi nodi hii inavyojitambulisha kwa mtandao.','How to share your work — send an email to:'=>'Jinsi ya kushiriki kazi yako — tuma barua pepe kwa:','HTTP %d'=>'HTTP %d','HTTP Signature verification failed.'=>'Uthibitishaji wa HTTP Signature umefeli.','https://agnosis.art'=>'https://agnosis.art','Icon'=>'Ikoni','Icon color'=>'Rangi ya ikoni','Icon settings'=>'Mipangilio ya ikoni','Icon size'=>'Ukubwa wa ikoni','Icon vertical align'=>'Mpangilio wa wima wa ikoni','Icon-only link to the artist’s biography.'=>'Kiungo cha ikoni pekee kwenda kwenye wasifu wa msanii.','Icon-only link to the artist’s events archive.'=>'Kiungo cha ikoni pekee kwenda kwenye hifadhi ya matukio ya msanii.','Icon-only links have no text baseline of their own — use this if they sit too high or low next to the artist name once Icon size is changed from the default.'=>'Viungo vya ikoni pekee havina msingi wa maandishi wao wenyewe — tumia hili ikiwa viko juu au chini sana karibu na jina la msanii baada ya Ukubwa wa ikoni kubadilishwa kutoka chaguo-msingi.','Idle'=>'Tulia','If the link was correct, its destination may simply not be from a source this site automatically embeds.'=>'Ikiwa kiungo kilikuwa sahihi, huenda tu lengwa lake halitokani na chanzo ambacho tovuti hii hujipachika kiotomatiki.','If you did not make this request, you can ignore this email — your account remains unchanged.'=>'Ikiwa hukuomba hili, unaweza kupuuza barua pepe hii — akaunti yako haijabadilika.','If you did not request this removal, simply ignore this email — nothing will be removed unless you click one of the buttons above.'=>'Ikiwa hukuomba uondoaji huu, puuza tu barua pepe hii — hakuna kitakachoondolewa hadi ubofye mojawapo ya vitufe vilivyo hapo juu.','If you did not request this removal, simply ignore this email — your %s will remain published.'=>'Ikiwa hukutoa ombi hili la kuondoa, puuza tu barua pepe hii — %s yako itabaki imechapishwa.','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'Kama hukuomba, pumzika tu na barua pepe hii — hakuna kinachotokea mpaka kiungo hiki kibonyezwe.','If you didn\'t request this, please contact the site admin right away.'=>'Ikiwa hukuomba hili, tafadhali wasiliana na msimamizi wa tovuti mara moja.','If you didn\'t request this, simply ignore this email — you will not be subscribed.'=>'Ikiwa hukuomba hili, puuza barua pepe hii tu — hutajisajili.','If you have questions, please contact the site admin.'=>'Ikiwa una maswali, tafadhali wasiliana na msimamizi wa tovuti.','If you made this request, click the link below to confirm. This action is permanent and cannot be undone.'=>'Ikiwa umefanya ombi hili, bofya kiungo kilicho hapa chini ili kuthibitisha. Kitendo hiki ni cha kudumu na hakiwezi kutenduliwa.','If you want to permanently remove this %s, click the button below. This action cannot be undone.'=>'Ikiwa unataka kuondoa kabisa %s hii, bofya kitufe kilicho hapa chini. Kitendo hiki hakiwezi kutenduliwa.','If your photo was taken on an iPhone, try switching Settings → Camera → Formats to "Most Compatible" before taking or sending it, or use "Options" in Mail to send it as a JPEG.'=>'Ikiwa picha yako ilipigwa kwa iPhone, jaribu kubadilisha Mipangilio → Kamera → Miundo kuwa "Inaoana zaidi" kabla ya kuipiga au kuituma, au tumia "Chaguo" katika Mail kuituma kama JPEG.','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'Picha hupunguzwa ukubwa kwa uwiano hadi upana huu kabla ya kutumwa kwa AI kwa maelezo — gharama ya tokeni za kuona huongezeka kulingana na azimio, na kazi ya maelezo huhitaji pikseli chache sana kuliko picha ya asili. Hii hutumika kwa upakiaji wa picha za kazi ya sanaa, kurasa za PDF zilizogeuzwa picha, na fremu za bango la video kwa pamoja. Weka kuwa 0 ili kutuma kila wakati picha zenye azimio kamili (hutumia tokeni zaidi, hakuna tofauti ya ubora kwa kazi za kawaida za maelezo). Inahitaji kiongezi cha PHP cha Imagick; picha hutumwa kwa ukubwa wake wa asili bila kujali mpangilio huu inapokosekana. Chaguo msingi: 800.','IMAP credentials are not configured.'=>'Vitambulisho vya IMAP havijasanidiwa.','IMAP host'=>'Seva pangishi ya IMAP','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','IMAP port'=>'Mlango wa IMAP','IMAP username'=>'Jina la mtumiaji la IMAP','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'Hukimbiza mara moja mlolongo wa AI kwenye vipengee vyote vya foleni vinavyosubiri bila kusubiri WP-Cron. Tumia hiki kujaribu mtiririko wa mwisho-kwa-mwisho baada ya kupokea.','In your language: %s'=>'Katika lugha yako: %s','Inbox'=>'Sanduku la Ingizo','Inbox retention (days)'=>'Uhifadhi wa kikasha (siku)','Inbox Tools'=>'Zana za Kisanduku pokezi','Include artist\'s name in preset title'=>'Jumuisha jina la msanii kwenye kichwa kilichowekwa awali','Instantly, one email per application (default).'=>'Papo hapo, barua pepe moja kwa kila ombi (chaguomsingi).','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'Maelekezo yanayopitishwa kwa mtoa huduma wa uboreshaji wa picha. Maelezo ya kazi ya sanaa yanayotolewa na AI huongezwa kiotomatiki kama muktadha.','Invalid or incomplete link.'=>'Kiungo si sahihi au hakijakamilika.','Invalid or missing webhook signature.'=>'Sahihi ya webhook si sahihi au haipo.','Invalid removal token.'=>'Tokeni ya uondoaji si sahihi.','Invalid review token.'=>'Tokeni ya ukaguzi si sahihi.','Invalid vote link.'=>'Kiungo cha kura si sahihi.','Invitation intro'=>'Utangulizi wa mwaliko','Invitation sent.'=>'Mwaliko umetumwa.','Invite an Artist'=>'Mwalike Msanii','IP address'=>'Anwani ya IP','is active and configured for'=>'iko hai na imesanidiwa kwa ajili ya','Issue'=>'Suala','Issue not found'=>'Toleo halijapatikana','Issue prepared and queued — it will go out over the next few cron cycles.'=>'Toleo limeandaliwa na kuwekwa kwenye foleni — litatumwa ndani ya mizunguko michache ijayo ya cron.','It\'s already saved and will be used as-is if you don\'t act — review it, rewrite it, or clear it back to blank here:'=>'Tayari imehifadhiwa na itatumika kama ilivyo usipochukua hatua — ikague, iandike upya, au ifute iwe tupu hapa:','Its subject line didn\'t exactly match one of your existing titles. If you meant to replace an existing artwork, "%s", resend your email with that exact title instead.'=>'Kichwa chake hakikulingana kikamilifu na moja ya vichwa vyako vilivyopo. Ikiwa ulimaanisha kuchukua nafasi ya kazi ya sanaa iliyopo, "%s", tuma tena barua pepe yako ikiwa na kichwa hicho hicho kabisa badala yake.','Its subject line didn\'t exactly match one of your existing titles. If you meant to update an existing event, "%s", resend your email with that exact title instead.'=>'Kichwa chake hakikulingana kikamilifu na moja ya vichwa vyako vilivyopo. Ikiwa ulimaanisha kusasisha tukio lililopo, "%s", tuma tena barua pepe yako ikiwa na kichwa hicho hicho kabisa badala yake.','Join'=>'Jiunge','Join Agnosis'=>'Jiunge na Agnosis','Joined'=>'Aliungana','just now'=>'hivi punde','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'Huhifadhiwa upande wa seva pekee — hutumika kuthibitisha kila uwasilishaji wa fomu moja kwa moja na Cloudflare kabla haujakubaliwa.','keyId in Signature header is not a valid URL.'=>'keyId katika kichwa cha Signature si URL halali.','Language'=>'Lugha','Language Router'=>'Kisafirishaji cha Lugha','Language you work in'=>'Lugha unayofanya kazi kwa','Last sent'=>'Iliyotumwa mara ya mwisho','Leave blank to ban indefinitely'=>'Acha tupu ili kumfungia kwa muda usiojulikana','Leave the date blank to ban indefinitely. Continue?'=>'Acha tarehe ikiwa tupu ili kumfungia kwa muda usiojulikana. Endelea?','Leave unset to match the block’s own text color.'=>'Acha bila kuwekwa ili ilingane na rangi ya maandishi ya kizuizi chenyewe.','Let artists submit other links too (AI-reviewed)'=>'Waruhusu wasanii pia kuwasilisha viungo vingine (vinakaguliwa na AI)','Lets a visitor message the current artist subdomain’s artist. Content is rendered live on the frontend, for the artist currently being viewed.'=>'Huruhusu mgeni kumtumia ujumbe msanii wa kikoa kidogo cha sasa cha msanii. Maudhui huonyeshwa moja kwa moja kwenye frontend, kwa msanii anayetarajiwa kuonyeshwa kwa sasa.','Level'=>'Kiwango','Lightning bolt'=>'Radi','Link error'=>'Hitilafu ya kiungo','Link expired or already used'=>'Kiungo muda wake umeisha au tayari kimetumiwa','Link settings'=>'Mipangilio ya kiungo','Link type'=>'Aina ya kiungo','Live'=>'Hai','Locale'=>'Mahali','Location'=>'Mahali','Log cleared.'=>'Rekodi zimefutwa.','Log in'=>'Ingia','Log in to view your submissions'=>'Ingia ili uone mawasilisho yako','Login username for the IMAP account — typically the catch-all mailbox address.'=>'Jina la mtumiaji la kuingia kwa akaunti ya IMAP — kwa kawaida anwani ya sanduku la barua la catch-all.','Logs'=>'Rekodi','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Ujumbe mrefu zaidi kwa anwani ya tangazo la Jumuiya hurudishwa kwa mtumaji badala ya kutangazwa — mtumaji huambiwa apunguze na atume tena. Hupimwa kwa herufi, si maneno, kwa hivyo hutumika kwa usawa katika lugha zisizotumia nafasi kati ya maneno (Kichina, Kijapani, Kithai, n.k.). Nakala ya kila mpokeaji hutafsiriwa kibinafsi, kwa hivyo hii pia inaweka kikomo kiasi ambacho ujumbe mmoja unaweza kugharimu katika simu za AI za tafsiri. Chaguo msingi: 2000. Kiwango cha juu kisichoweza kuvukwa: 20000, bila kujali mpangilio huu.','Looks great — Publish it'=>'Inaonekana vizuri — Chapisha','Mail from (workflow)'=>'Mail from (workflow)','Mail from: email address'=>'Barua kutoka: anwani ya barua pepe','Mail from: name'=>'Barua kutoka: jina','Make any final changes below, or leave everything as-is to publish exactly what was drafted.'=>'Fanya mabadiliko yoyote ya mwisho hapa chini, au acha kila kitu kama kilivyo ili kuchapisha hasa kilichoundwa.','Make changes'=>'Fanya mabadiliko','Make sure the body only contains your own, original text and attachment — no quoted or forwarded content from an earlier message.'=>'Hakikisha mwili una maandishi yako mwenyewe ya asili na kiambatisho tu — hakuna yaliyotajwa moja kwa moja au yaliyotumwa mbele kutoka kwa ujumbe wa awali.','Manage notification preferences'=>'Dhibiti mapendeleo ya arifa','Manage notification preferences: %s'=>'Dhibiti mapendeleo ya arifa: %s','Mark artworks under this medium as sensitive content by default'=>'Mark artworks under this medium as sensitive content by default','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'Idadi ya juu ya ujumbe ambao mgeni yuleyule (kwa anwani ya barua pepe) anaweza kumtumia msanii mmoja ndani ya dirisha lililo hapa chini — linatumika katika matoleo yote ya lugha ya ukurasa wa msanii huyo. Chaguo-msingi: 2.','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'Idadi ya juu ya wasanii waliokubaliwa. Inapojazwa, maombi mapya huingia kwenye orodha ya kusubiri badala ya kukataliwa, na nafasi inayowaziwa humpokea anayefuata. Weka 0 kwa bila kikomo. Jamii pia inaweza kupiga kura kubadilisha hili.','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'Idadi ya juu ya ujumbe ambao msanii mmoja anaweza kutuma kwa anwani ya tangazo la Jumuiya (Mipangilio → Barua pepe) kwa siku. Huzuia mwanachama mmoja kujaza kikasha cha kila mwanachama mwingine. Chaguo msingi: 3.','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'Idadi ya juu ya barua pepe za uthibitisho za kujiondoa ("kwaheri") ambazo anwani moja ya mtumaji inaweza kusababisha kwa siku. Kujiondoa halisi kunahitaji kuombwa mara moja tu — hii inaweka kikomo idadi ya barua pepe za uthibitisho ambazo From iliyoghushiwa au inayorudiwa inaweza kutumia kumtumia msanii halisi barua taka. Chaguo msingi: 3.','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'Idadi ya juu ya mawasilisho yanayokubaliwa kutoka kwa msanii mmoja kwa saa, kupitia IMAP na pia ingizo la webhook. Kuzidisha kikomo hiki huangusha ujumbe kimyakimya (hakuna kurudia kutoka kwa ESPs). Chaguo-msingi: 5.','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'Idadi ya juu ya maneno kwa dondoo la sentensi moja. Inatajwa kama {excerpt_words} katika amri ya mfumo.','Medium'=>'Kati','Mediums'=>'Vitu vya kati','Member Removed'=>'Mwanachama Ameondolewa','Members'=>'Wanachama','Merge biography updates with AI'=>'Unganisha masasisho ya wasifu kwa AI','Message'=>'Ujumbe','Message deleted.'=>'Ujumbe umefutwa.','Middle'=>'Kati','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Mfano unaotumika kwa maelezo ya kazi ya sanaa wakati Anthropic ndiye mtoa maelezo. Lazima iunge mkono ingizo la kuona.','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'Muundo unaotumika kwa maelezo ya kazi ya sanaa wakati OpenAI ndiye mtoa huduma wa maelezo. Lazima iunge mkono ingizo la kuona.','Model used for image enhancement when OpenAI is the enhancement provider.'=>'Muundo unaotumika kwa uboreshaji wa picha wakati OpenAI ndiye mtoa huduma wa uboreshaji.','Mute community broadcast messages from other artists.'=>'Nyamazisha ujumbe wa matangazo ya jumuiya kutoka kwa wasanii wengine.','My Submissions'=>'Maombi Yangu','Name'=>'Jina','Name shown as the sender of admission, vote, welcome, departure, invitation, and submission-review emails. Leave blank to use the site name.'=>'Jina linaloonyeshwa kama mtumaji wa barua pepe za kuingizwa, kupiga kura, kukaribishwa, kuondoka, mwaliko, na ukaguzi wa uwasilishaji. Acha wazi ili kutumia jina la tovuti.','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'Jina linaloonyeshwa kama mtumaji wa barua pepe za muhtasari. Acha tupu ili kutumia jina la tovuti.','Network'=>'Mtandao','Never'=>'Kamwe','New application: %1$s wants to join %2$s'=>'Ombi jipya: %1$s anataka kujiunga na %2$s','New Artwork'=>'Kazi Mpya ya Sanaa','New artwork'=>'Kazi mpya za sanaa','New Biography'=>'Wasifu Mpya','New Event'=>'Tukio Jipya','New Medium Name'=>'Jina la Kati Mpya','New message from %s via your Agnosis contact form'=>'Ujumbe mpya kutoka %s kupitia fomu yako ya mawasiliano ya Agnosis','Newsletter'=>'Jarida la habari','Newsletter archive'=>'Hifadhi ya jarida','Newsletter archive — %s'=>'Hifadhi ya jarida — %s','Newsletter Popover — opens the signup form'=>'Popo inayojitokeza ya Jarida — hufungua fomu ya kujisajili','Newsletter settings'=>'Mipangilio ya jarida','Newsletter Signup'=>'Usajili wa jarida','Newsletter Status'=>'Hali ya Jarida','Next'=>'Ifuatayo','No account needed to apply — the community reviews and votes on every application.'=>'Hakuna akaunti inayohitajika ili kuomba — jumuiya hukagua na kupiga kura kwa kila ombi.','No active membership found for this account.'=>'Hakuna uanachama hai uliopatikana kwa akaunti hii.','No active proposal to co-sign.'=>'Hakuna pendekezo linalofanya kazi la kulisupporti kwa pamoja.','No address configured'=>'Hakuna anwani iliyosanidiwa','No admitted members yet.'=>'Bado hakuna wanachama waliokubaliwa.','No artworks found.'=>'Hakuna kazi za sanaa zilizopatikana.','No artworks in trash.'=>'Hakuna kazi za sanaa kwenye taka.','No biographies found.'=>'Hakuna wasifu uliopatikana.','No biographies in trash.'=>'Hakuna wasifu kwenye taka.','No contact messages yet.'=>'Bado hakuna ujumbe wa mawasiliano.','No earlier version of this photo was found.'=>'Hakuna toleo la awali la picha hii lililopatikana.','No events found.'=>'Hakuna matukio yaliyopatikana.','No events in trash.'=>'Hakuna matukio kwenye taka.','No failed recipients to retry for this newsletter.'=>'Hakuna wapokeaji walioshindwa wa kujaribu tena kwa jarida hili.','No image file was received.'=>'Hakuna faili la picha lililopokelewa.','No issues have gone out yet — check back soon.'=>'Hakuna matoleo yaliyotumwa bado — angalia tena hivi karibuni.','no limit'=>'hakuna kikomo','No log entries yet.'=>'Bado hakuna maingizo ya logi.','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'Hakuna kuingia kunahitajika kufanya kazi na Agnosis — yote yaliyo juu hutokea kwa barua pepe. Ukipenda pia kutumia vipengele vya hiari vya mtandaoni vya tovuti (kama kuchungulia uwasilishaji kabla ya kuchapishwa), unaweza kuweka nenosiri wakati wowote ukitumia','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'Hakuna ujumbe kwenye foleni bado. Bofya "Pokea Sanduku la Ingizo" ili kuchukua ujumbe kutoka akaunti yako ya IMAP.','No messages match this filter.'=>'Hakuna ujumbe unaolingana na kichujio hiki.','No pending applications.'=>'Hakuna maombi yanayosubiri.','No pending removal request found for this item.'=>'Hakuna ombi la uondoaji linalosubiri kwa bidhaa hii.','No Privacy Policy page is set.'=>'Hakuna ukurasa wa Sera ya Faragha uliowekwa.','No queue rows match this filter.'=>'Hakuna safu za foleni zinazolingana na kichujio hiki.','No submissions awaiting review.'=>'Hakuna uwasilishaji unaosubiri ukaguzi.','No such artist actor.'=>'No such artist actor.','No text-generation model configured. Set one up under Settings → Connectors.'=>'Hakuna modeli ya kuzalisha maandishi iliyosanidiwa. Sanidi moja chini ya Mipangilio → Viunganishi.','Node label'=>'Lebo ya nodi','Node public key'=>'Funguo ya umma ya nodi','Node URL is required.'=>'URL ya Node inahitajika.','None'=>'Hakuna','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'Hakuna hata moja ya programu-jalizi za kawaida za kutuma SMTP iliyogunduliwa — tovuti hii huenda inategemea PHP mail() iliyojengewa ndani, ambayo wapangishaji wengi huiwasilisha vibaya.','Not found'=>'Haijapatikana','Nothing new to report this time — but the community is still here, and the next issue will have more.'=>'Hakuna jipya la kuripoti wakati huu — lakini jumuiya bado ipo, na toleo lijalo litakuwa na zaidi.','Nothing tied to you — your artwork, biography, events, or account details — is stored on %s anymore.'=>'Hakuna chochote kinachohusiana nawe — kazi yako ya sanaa, wasifu, matukio, au maelezo ya akaunti — kinachohifadhiwa tena kwenye %s.','Notice box background color'=>'Rangi ya usuli ya kisanduku cha ilani','Notification preferences'=>'Mapendeleo ya arifa','Notified %d artist(s) immediately.'=>'Iliarifu msanii %d mara moja.','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'Idadi ya uteuzi wa wasanii unaohitajika kabla ya kura ya jamii ya kuondoa kufunguliwa. Wasimamizi wanaweza kuruka kizingiti hiki.','Number of tags'=>'Idadi ya tagi','Old row — delete and re-poll to preview'=>'Safu ya zamani — futa na fanya upatikanaji upya ili kutazama hakikisho','Older →'=>'Ya zamani zaidi →','On the site: %s'=>'Kwenye tovuti: %s','Once a day, a single digest of every application still awaiting my vote.'=>'Mara moja kwa siku, muhtasari mmoja wa kila ombi ambalo bado linasubiri kura yangu.','Once it\'s a fresh, original message, just send it to the same address again — we\'ll pick it up automatically.'=>'Mara tu itakapokuwa ujumbe mpya kabisa, wa asili, utume tena kwenye anwani ile ile — tutajichukua kiotomatiki.','Once it\'s properly attached, just send it to the same address again — we\'ll pick it up automatically.'=>'Mara itakapokuwa imeambatishwa ipasavyo, itume tu tena kwenye anwani ileile — tutaipata kiotomatiki.','Once you have a clearer photo, just email it to the same address as before — we\'ll pick it up automatically.'=>'Ukishapata picha iliyo wazi zaidi, itume tu kwa barua pepe kwenye anwani ileile kama hapo awali — tutaichukua kiotomatiki.','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'Kila jina la mwenyeji kwa mstari mmoja. Kiungo kilichowasilishwa kinakuwa embed tajiri mara moja ikiwa kinalingana na mojawapo ya haya (au kikoa kidogo chake) — hakuna ukaguzi wa AI unaohitajika, hakuna ombi la mtandao linalofanywa kwa kiungo chenyewe.','One last step before %s can review your application: confirm this is really your email address.'=>'Hatua ya mwisho kabla ya %s kuweza kukagua ombi lako: thibitisha kuwa hili kweli ni anwani yako ya barua pepe.','One-line description'=>'Maelezo ya mstari mmoja','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'Maduka ya mtandaoni, matangazo, kurasa za kutua za uuzaji. Huzima kwa chaguo-msingi — msanii kuunganisha duka linalouza machapisho yake mwenyewe ni jambo la kawaida na si la kuhitajika kiasili. Hufanya kazi tu wakati ukaguzi wa AI (hapo juu) umewashwa.','Only admitted artists can vouch.'=>'Ni wasanii waliokubaliwa pekee wanaoweza kutoa udhamini.','Only admitted artists may edit their own content.'=>'Ni wasanii waliokubaliwa pekee wanaweza kuhariri maudhui yao wenyewe.','Only community members can do this.'=>'Ni wanachama wa jumuiya pekee wanaoweza kufanya hivi.','Only published content can be corrected here.'=>'Ni maudhui yaliyochapishwa pekee yanaweza kusahihishwa hapa.','Only takes effect when AI review (above) is enabled.'=>'Hufanya kazi tu wakati ukaguzi wa AI (hapo juu) umewashwa.','Open a community removal vote for this artist? All members will be emailed.'=>'Fungua kura ya kuondoa kwa jumuiya kwa msanii huyu? Wanachama wote watatumwa barua pepe.','Open LinguaForge Settings'=>'Fungua Mipangilio ya LinguaForge','Open Vote'=>'Fungua Kura','Open your submissions page →'=>'Fungua ukurasa wako wa mawasilisho →','OpenAI'=>'OpenAI','OpenAI API key'=>'Ufunguo wa API wa OpenAI','OpenAI API key not configured.'=>'Ufunguo wa API wa OpenAI haujasanidiwa.','OpenAI connection successful.'=>'Muunganisho wa OpenAI umefanikiwa.','OpenAI image model'=>'Mfano wa picha wa OpenAI','OpenAI text model'=>'OpenAI text model','OpenAI vision model'=>'Muundo wa OpenAI wa kuona','Opens a popover with a form to message the artist directly. Hidden automatically if the artist has turned contact messages off.'=>'Hufungua dirisha ibukizi lenye fomu ya kumtumia msanii ujumbe moja kwa moja. Hufichwa kiotomatiki ikiwa msanii amezima ujumbe wa mawasiliano.','OpenSSL is required for HTTP Signature verification.'=>'OpenSSL inahitajika kwa uthibitishaji wa HTTP Signature.','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'Njia ya kujiondoa kwa wapiga picha na wasanii wanaotegemea lenzi ambao picha yao ndiyo kazi ya sanaa, si picha tu ya kazi hiyo. Mawasilisho hapa huchapishwa kwa picha asili kama ilivyotumwa, bila kubadilishwa — uboreshaji wa AI hurukwa na lango la kukataa kwa ubora hupitishwa. Ufafanuzi wa AI (kichwa, lebo, alt text) bado hufanywa. Tumia kiashiria cha somo [Photo] kama mbadala kwa wateja wa barua pepe wasiounga mkono To: aliases — kwa mfano photo@agnosis.art','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Dokezo la hiari linalowekwa kabla ya toleo linalofuata la msanii pekee — hufutwa kiotomatiki mara tu toleo hilo linapopangwa kwenye foleni. Acha tupu ili kutuma auto-digest bila utangulizi. Ikiwa litaachwa tupu, Agnosis hutayarisha moja kiotomatiki kutoka kwa mambo mapya karibu siku moja kabla ya toleo kutumwa, na hukutumia barua pepe ili ulihakiki kwanza — andika yako hapa wakati wowote ili kuruka hilo.','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'Dokezo la hiari linalowekwa kabla ya toleo linalofuata la umma pekee — hufutwa kiotomatiki mara tu toleo hilo linapopangwa kwenye foleni. Ikiwa litaachwa tupu, Agnosis hutayarisha moja kiotomatiki kutoka kwa mambo mapya karibu siku moja kabla ya toleo kutumwa, na hukutumia barua pepe ili ulihakiki kwanza — andika yako hapa wakati wowote ili kuruka hilo.','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'Hiari — eleza aina nyingine yoyote ya maudhui ambayo AI inapaswa kukataa, kwa lugha ya kawaida (k.m. "matamshi ya chuki au maudhui ya vurugu ya msimamo mkali", "kurasa za hadaa au ulaghai"). Hufanya kazi tu wakati ukaguzi wa AI (hapo juu) umewashwa.','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'Hiari — chagua ukurasa unaoeleza mchakato wa uthibitisho na kinachofuata. Ombi likifanikiwa kuwasilishwa, msanii ataelekezwa huko badala ya kuona tu ujumbe wa uthibitisho ndani ya ukurasa. Acha kama "Hakuna" ili kubaki na ujumbe wa ndani tu.','Or simply resend your original email with that exact title.'=>'Au tuma tena barua pepe yako ya awali ikiwa na kichwa hicho hicho kabisa.','Original message, as submitted:'=>'Ujumbe asili, kama ulivyowasilishwa:','Other'=>'Nyingine','Page %1$d of %2$d'=>'Ukurasa %1$d kati ya %2$d','Page background color'=>'Rangi ya usuli ya ukurasa','Part of the artwork appears to be cropped out of the frame. Step back and make sure the entire work is visible before shooting.'=>'Sehemu ya kazi ya sanaa inaonekana imekatwa kutoka kwenye fremu. Sogea nyuma na hakikisha kazi nzima inaonekana kabla ya kupiga picha.','Password'=>'Nenosiri','password recovery'=>'urejeshaji wa nenosiri','Past issues of the %s newsletter.'=>'Matoleo ya awali ya jarida la %s.','Past newsletter delivery records were anonymized; per-issue delivery counts were kept for statistics.'=>'Rekodi za awali za uwasilishaji wa jarida zilifichwa utambulisho; hesabu za uwasilishaji kwa kila toleo ziliwekwa kwa ajili ya takwimu.','Path prefix (subfolder)'=>'Kiambishi cha njia (subfolder)','Pending'=>'Inasubiri','Pending Applications'=>'Maombi Yanayosubiri','Per-artist contact limit'=>'Kikomo cha mawasiliano kwa kila msanii','Per-artist contact limit window (hours)'=>'Dirisha la kikomo cha mawasiliano kwa kila msanii (saa)','Per-sender hourly submission limit'=>'Kikomo cha uwasilishaji kwa saa kwa kila mtumaji','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'Asilimia ya wasanii hai wanaopaswa kupiga kura ya ndiyo ili kujiunga. Huchanganywa na kiwango cha chini kilicho hapa chini.','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'Asilimia inayobaki kwa nodi hii kwenye michango na mauzo ya sanaa. Wasanii hawalipi chochote awali.','Permanently delete this artist and all their content? This cannot be undone.'=>'Ufute kabisa msanii huyu na maudhui yake yote? Hili haliwezi kutenguliwa.','Permission denied.'=>'Ruhusa imekataliwa.','Person'=>'Mtu','Photo'=>'Picha','Photo replaced — the original is kept and can be restored later.'=>'Picha imebadilishwa — asili imehifadhiwa na inaweza kurejeshwa baadaye.','Photo-only'=>'Picha pekee','Photo-only address'=>'Anwani ya picha pekee','Photo-only — publish as-is, no AI enhancement'=>'Picha pekee — chapisha kama ilivyo, bila uboreshaji wa AI','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'Picha zinazopata alama sawa na au chini ya thamani hii (1–10) hukataliwa kiotomatiki — msanii hupokea barua pepe ya kirafiki ikieleza tatizo na anaalikwa kutuma tena. Alama 0 huzima kukataliwa kiotomatiki. Lazima iwe chini kuliko kizingiti cha uboreshaji. Chaguo-msingi: 3.','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'Picha zinazopata alama chini ya thamani hii (1–10) huimarishwa kiotomatiki. Alama 10 = picha kamili, 1 = haitumiki kiufundi. Chaguo-msingi: 7 — ni picha zenye matatizo yanayoonekana pekee ndizo huchakatwa. Weka 1 ili kuzima kabisa uboreshaji wa kiotomatiki.','Pick something that won’t blend in with icons already sitting next to it (e.g. Social Share).'=>'Chagua kitu kisichochanganyika na ikoni zilizo tayari karibu nayo (k.m. Kushiriki Kijamii).','Pin'=>'Pini','Pipeline Logs'=>'Kumbukumbu za Mlalo','Place this block on your /join/ page or in a Site Editor page template assigned to that page.'=>'Weka kizuizi hiki kwenye ukurasa wako wa /join/ au kwenye kiolezo cha ukurasa cha Site Editor kilichogawiwa ukurasa huo.','Please complete the verification check and try again.'=>'Tafadhali kamilisha uthibitishaji kisha ujaribu tena.','Please enter a valid email address to send the test to.'=>'Tafadhali ingiza anwani halali ya barua pepe ili kutuma jaribio.','Please enter a valid email address.'=>'Tafadhali ingiza anwani halali ya barua pepe.','Please fill in all required fields.'=>'Tafadhali jaza sehemu zote zinazohitajika.','Please select your language.'=>'Tafadhali chagua lugha yako.','Please try sending it again with plain text included.'=>'Tafadhali jaribu kuituma tena ukiambatanisha maandishi ya kawaida.','Please upload a JPEG, PNG, WebP, or GIF image.'=>'Tafadhali pakia picha ya JPEG, PNG, WebP, au GIF.','Polish biography with AI'=>'Wasifu wa mwandishi ulioboreshwa kwa AI','Polish events with AI'=>'Matukio yaliyoimarishwa kwa AI','Poll complete. %d new message(s) added to the queue.'=>'Upatikanaji umekamilika. Ujumbe mpya %d umeongezwa kwenye foleni.','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'Upatikanaji umekamilika. Ujumbe mpya %d umeongezwa kwenye foleni. Angalia kichupo cha Rekodi, kisha bofya Chakata Foleni Inayosubiri.','Poll Inbox'=>'Fanya upatikanaji wa Inbox','Poll Inbox Now'=>'Pokea Kisanduku Pokezi Sasa','Poll inbox now'=>'Pokea kisanduku pokezi sasa','Portfolio link'=>'Kiungo cha jalada','Portfolio URL'=>'URL ya jalada','Portfolio ↗'=>'Portfolio ↗','Portfolio:'=>'Kwingineko:','Prefer these one at a time again? You can switch back any time from your notification preferences link below.'=>'Unapendelea haya yaonekane moja moja tena? Unaweza kurudi wakati wowote kupitia kiungo cha mapendeleo yako ya arifa hapa chini.','Preferences saved'=>'Mapendeleo yamehifadhiwa','Preset biography title'=>'Kichwa cha wasifu kilichowekwa awali','Prev'=>'Zilizotangulia','Preview'=>'Hakikisho','Previous'=>'Zilizo nyuma','Primary text color'=>'Rangi ya msingi ya maandishi','Primary text size (px)'=>'Ukubwa wa msingi wa maandishi (px)','Privacy Policy'=>'Sera ya Faragha','Process'=>'Chakata','Process All Pending'=>'Chakata Vyote Vinavyosubiri','Process Pending Queue'=>'Chakata Foleni Zinazosubiri','Process queue'=>'Chakata foleni','Processed'=>'Imechakwa','Processed %d pending item(s).'=>'Vipengee vinavyosubiri %d vimechakwa.','Processed %d pending queue item(s). Check the Logs tab for details.'=>'Vipengee %d vya foleni vinavyosubiri vimechakwa. Angalia kichupo cha Rekodi kwa maelezo.','Processing'=>'Inachakata','Promote'=>'Tangaza','Promote artwork address'=>'Anwani ya kukuza kazi ya sanaa','Proposal not found.'=>'Pendekezo halikupatikana.','Public'=>'Ya umma','Public application form for new artists. Submits name, email, bio, portfolio URL and a personal statement to the community for review. Content is rendered live on the frontend.'=>'Fomu ya maombi ya umma kwa wasanii wapya. Hutuma jina, barua pepe, wasifu, URL ya jalada la kazi na tamko binafsi kwa jamii kwa ajili ya ukaguzi. Maudhui huonyeshwa moja kwa moja kwenye frontend.','Public newsletter'=>'Jarida la umma','Public newsletter frequency (days)'=>'Mzunguko wa jarida la umma (siku)','Public newsletter intro'=>'Utangulizi wa jarida la umma','Publish a photo exactly as sent — no AI enhancement, no quality check.'=>'Chapisha picha kama ilivyotumwa — bila uboreshaji wa AI, bila ukaguzi wa ubora.','Publish exactly as sent — no AI at all, not even the title/description pass.'=>'Chapisha kama ilivyotumwa moja kwa moja — bila AI kabisa, hata hatua ya kichwa/maelezo.','Publish it'=>'Ichapishe','Publish this %s?'=>'Kuchapisha %s hii?','Published'=>'Imechapishwa','Published ✓'=>'Imechapishwa ✓','Publishing…'=>'Inachapisha…','Pure'=>'Halisi','Pure address (no AI at all)'=>'Anwani ya Pure (hakuna AI hata kidogo)','Pure — publish exactly as sent, no AI at all'=>'Safi — chapisha kwa usahihi kama ilivyotumwa, bila AI hata kidogo','Queue #%d sent to pipeline. Check back in a few seconds.'=>'Safu ya foleni #%d imetumwa kwenye bomba la uchakataji. Rudi baada ya sekunde chache.','Queue row deleted. Poll Inbox to re-fetch the message.'=>'Safu ya foleni imefutwa. Fanya upatikanaji wa Inbox upya ili kufetch ujumbe tena.','Queued at'=>'Iliwekwa foleni tarehe','Received'=>'Imepokelewa','Recent work from the community'=>'Kazi za hivi karibuni kutoka kwa jumuiya','Recipient type'=>'Aina ya mpokeaji','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'Wapokeaji wanaotumiwa barua pepe katika kila mzunguko wa cron wa dakika 5. Punguza hili ikiwa hosti yako inaweka kikomo cha kasi ya barua zinazotoka; ongeza kwa uwasilishaji wa haraka zaidi kwenye hosti zenye mipaka ya ukarimu.','Reject'=>'Kataa','Rejected'=>'Iliyokataliwa','Rejection reason'=>'Sababu ya kukataliwa','Rejection threshold (quality score)'=>'Kizingiti cha kukataliwa (alama ya ubora)','Remember me'=>'Nikumbuke','Removal nominations required'=>'Uteuzi unaohitajika wa kuondoa','Removal request address'=>'Anwani ya ombi la kuondolewa','Removal request not found.'=>'Ombi la uondoaji halikupatikana.','Removal vote window (days)'=>'Dirisha la kura la kuondoa (siku)','Remove'=>'Ondoa','Remove artwork (subject: exact title)'=>'Ondoa kazi ya sanaa (somo: kichwa halisi)','Remove this artwork?'=>'Ondoa kazi hii ya sanaa?','Replace'=>'Badilisha','Replace artwork (subject: exact title)'=>'Badilisha kazi ya sanaa (somo: kichwa halisi)','Replace artwork address'=>'Badilisha anwani ya kazi ya sanaa','Replace photo'=>'Badilisha picha','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'Hubadilisha maandishi yaliyo juu na chaguo-msingi lililojengwa ndani la programu-jalizi — bofya Hifadhi Mabadiliko hapa chini ili kulihifadhi.','Reprocess'=>'Chakata Upya','Request an existing artwork or event be taken down — subject must match its title.'=>'Omba kazi iliyopo au tukio liondolewe — somo lazima lilingane na kichwa chake.','Request date is too old or too far in the future.'=>'Tarehe ya ombi ni ya zamani sana au iko mbali sana katika siku zijazo.','Require SPF/DKIM authentication'=>'Hitaji uthibitishaji wa SPF/DKIM','required'=>'inahitajika','Required when Anthropic is the description provider.'=>'Unahitajika wakati Anthropic ndiye mtoa huduma wa maelezo.','Required when OpenAI is the description or enhancement provider.'=>'Unahitajika wakati OpenAI ndiye mtoa huduma wa maelezo au uboreshaji.','Resend your original email with that exact title.'=>'Tuma tena barua pepe yako ya awali ikiwa na kichwa hicho hicho kabisa.','Reset'=>'Weka upya','Reset to default'=>'Rudisha kwenye chaguo-msingi','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'Huwarejesha mistari ya foleni iliyoshindikana/kwama/yatima kuwa inasubiri, kisha hupokea mara moja ujumbe ambao haujachakatwa. Kisha bofya "Chakata Foleni Zinazosubiri" ili kuendesha mlolongo wa AI. Kazi za sanaa ambazo tayari zimechapishwa zenye machapisho halali hazitachakatwa tena kamwe.','Resolved application retention (days)'=>'Siku za kubaki kwa ombi lililomalizwa','Resolved at'=>'Ilitatuliwa tarehe','Restore earlier photo'=>'Rejesha picha ya awali','Restored the earlier photo.'=>'Imerejesha picha ya awali.','Restoring…'=>'Inarejeshwa…','Retention varies by data type; see this site\'s administrator for specifics. You can request a copy of, or the erasure of, the personal data described above at any time using this site\'s standard WordPress data request tools.'=>'Muda wa kuhifadhi hutofautiana kulingana na aina ya data; muulize msimamizi wa tovuti hii kwa maelezo mahususi. Unaweza kuomba nakala ya, au ufutaji wa, data binafsi iliyoelezwa hapo juu wakati wowote kwa kutumia zana za kawaida za WordPress za maombi ya data za tovuti hii.','Retry Failed'=>'Jaribu Tena Zilizoshindikana','Review link expiry (days)'=>'Kuisha kwa kiungo cha ukaguzi (siku)','Review link not found or already used.'=>'Kiungo cha ukaguzi hakikupatikana au tayari kimetumiwa.','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'Kikoa kikuu kwa subdomain za wasanii, kwa mfano agnosis.art. Kila msanii anaweza kufikiwa katika nicename.{base_domain}. Inahitaji rekodi ya DNS ya wildcard (*.{base_domain}) inayoelekeza kwenye seva hii. Acha wazi ili kuzima uelekezaji wa subdomain.','routing mode'=>'hali ya uelekezaji','Rules'=>'Sheria','Running…'=>'Inaendelea…','Sample button'=>'Kitufe cha mfano','Save'=>'Hifadhi','Save &amp; Publish'=>'Hifadhi &amp; Chapisha','Save Changes'=>'Hifadhi Mabadiliko','Save preferences'=>'Hifadhi mapendeleo','Saved — translations will update within a few minutes.'=>'Imehifadhiwa — tafsiri zitajisasisha ndani ya dakika chache.','Saving and publishing…'=>'Inaokoa na kuchapisha…','Saving…'=>'Inahifadhiwa…','Search Artworks'=>'Tafuta Kazi za Sanaa','Search Biographies'=>'Tafuta Wasifu','Search Events'=>'Tafuta Matukio','Search Mediums'=>'Tafuta Vitu vya kati','Secondary text color'=>'Rangi ya maandishi ya pili','Secondary text size (px)'=>'Ukubwa wa pili wa maandishi (px)','See our %s for details.'=>'Tazama %s yetu kwa maelezo zaidi.','See past issues'=>'Ona matoleo yaliyopita','Select Image'=>'Chagua Picha','Select your language'=>'Chagua lugha yako','Self-hosting comfort threshold'=>'Kizingiti cha starehe cha kujihostia','Self-removal (goodbye) requests per sender per day'=>'Maombi ya kujiondoa (kwaheri) kwa kila mtumaji kwa siku','Send a message to every other artist in the community.'=>'Tuma ujumbe kwa kila msanii mwingine katika jamii.','Send a new version of an existing artwork — subject must match its title.'=>'Tuma toleo jipya la kazi iliyopo — somo lazima lilingane na kichwa chake.','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'Tuma barua pepe ya mara moja kumwalika mtu atume ombi. Hakuna kinachofuatiliwa au kuratibiwa — hii hutumwa mara moja kwa anwani iliyo hapa chini.','Send a real test email to:'=>'Tuma barua pepe ya majaribio halisi kwa:','Send a test'=>'Tuma jaribio','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'Tuma barua pepe yoyote (hakuna kiambatisho kinachohitajika). Utapokea kiungo cha uthibitisho — hakuna kitakachofutwa mpaka ukibofya.','Send batch size'=>'Ukubwa wa kundi la kutuma','Send Invitation'=>'Tuma Mwaliko','Send message'=>'Tuma ujumbe','Send new artwork to be published.'=>'Tuma kazi mpya ili ichapishwe.','Send Now'=>'Tuma Sasa','Send Test'=>'Tuma Jaribio','Sender email address'=>'Anwani ya barua pepe ya mtumaji','Sender name'=>'Jina la mtumaji','Sending…'=>'Inatuma…','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'Hutuma ping ndogo ("Jibu kwa neno: ping") kwa kutumia ufunguo wa API uliosanidiwa.','Sends a minimal ping using the configured API key.'=>'Hutuma ping ndogo kwa kutumia ufunguo wa API uliosanidiwa.','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'Hutuma barua pepe moja ya maandishi-tupu kutoka kwa utambulisho ule ule wa jamii unaotumika kwa barua za ukaguzi/kupiga kura/kudhamini. Kufika kwenye kisanduku chako cha barua ni ishara nzuri; kuingia kwenye taka au kutofika kabisa kunathibitisha tatizo halisi la uwasilishaji bila kujali yale ambayo ukaguzi wa juu unasema.','Sensitive by default'=>'Sensitive by default','Sensitive content'=>'Sensitive content','Sent'=>'Iliotumwa','Sent at'=>'Iliotumwa tarehe','Sent to artist'=>'Iliotumwa kwa msanii','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'Hutumika kwa AI kama maagizo ya mfumo. Tumia {tag_count} na {excerpt_words} kama tokoni — hubadilishwa na thamani zilizo hapa chini.','Settings'=>'Mipangilio','Shoot straight on — hold your phone parallel to the canvas to avoid perspective distortion.'=>'Piga picha moja kwa moja — shikilia simu yako sambamba na turubai ili kuepuka upotoshaji wa mtazamo.','Short bio'=>'Wasifu mfupi','Short description'=>'Maelezo mafupi','Shown in the header of outgoing HTML emails (submission review, removal confirmation, rejection notice, invitations, and both newsletters) in place of the plain "✦ Site Name" text. Leave empty to keep the text wordmark. Displayed at up to 40px tall — any width or aspect ratio works.'=>'Huonyeshwa kwenye kichwa cha barua pepe za HTML zinazotumwa nje (ukaguzi wa uwasilishaji, uthibitisho wa kuondolewa, ilani ya kukataliwa, mialiko, na nyuzi zote mbili za jarida) badala ya maandishi ya kawaida ya "✦ Jina la Tovuti". Acha wazi ili kubaki na maandishi ya jina la chapa. Huonyeshwa hadi urefu wa 40px — upana au uwiano wowote unafanya kazi.','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'Huonyeshwa karibu na juu ya barua pepe ya "Tuma Mwaliko" hapa chini (kiungo cha "Omba kujiunga" na jina la tovuti hufuata kiotomatiki — hakuna haja ya kuongeza mojawapo hapa). Aya mbili au tatu fupi zinatosha. Nakala ya kudumu, haifutwi baada ya matumizi kama utangulizi wa jarida hapo juu — hutafsiriwa kiotomatiki mwaliko ukitumwa katika lugha tofauti na ya tovuti yenyewe.','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'Urefu wa upande wa ukubwa wa mraba wa agnosis-thumb unaotumika katika kadi za uwasilishaji na dashibodi. Chaguo-msingi: 512. Picha zilizopo zinahitaji kuzalishwa upya baada ya kubadilisha thamani hii.','Signature header is missing required fields (keyId, headers, signature).'=>'Kichwa cha sahihi hakina sehemu zinazohitajika (keyId, headers, signature).','Signature header is required.'=>'Kichwa cha sahihi kinahitajika.','Signature keyId does not belong to the activity actor.'=>'Signature keyId haishughulikii na mtendaji wa shughuli.','Signature must cover the Date header.'=>'Signature must cover the Date header.','Signature on a POST request must cover the Digest header.'=>'Signature on a POST request must cover the Digest header.','Signature value is not valid base64.'=>'Thamani ya sahihi si base64 halali.','Skip SSL certificate validation'=>'Ruka uthibitishaji wa cheti cha SSL','Skipped'=>'Imerukwa','SMTP plugin'=>'Programu-jalizi ya SMTP','Social link %d (optional)'=>'Kiungo cha kijamii %d (si lazima)','Something went wrong.'=>'Kuna kitu kimekwenda vibaya.','Something went wrong. Please try again.'=>'Kulikuwa na tatizo. Tafadhali jaribu tena.','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'Barua taka, ulaghai, au matangazo ya kibiashara yasiyoombwa yasiyohusiana na kuwasiliana na msanii kwa kweli kuhusu kazi zake','Speech bubble'=>'Puto la mazungumzo','SPF record'=>'Rekodi ya SPF','Spotted something to fix after publishing? Log in and look for the pencil icon on your published page — you can correct the title, text, or photo yourself, no need to email us again.'=>'Umeona kitu cha kurekebisha baada ya kuchapisha? Ingia na utafute ikoni ya penseli kwenye ukurasa wako uliochapishwa — unaweza kusahihisha kichwa, maandishi, au picha mwenyewe, huna haja ya kututumia barua pepe tena.','Star'=>'Nyota','Start a brand new message rather than replying to or forwarding a previous one — this is always the most reliable way to reach us.'=>'Anza ujumbe mpya kabisa badala ya kujibu au kutuma mbele ujumbe wa awali — hili daima ndilo njia ya kuaminika zaidi ya kutufikia.','Statement'=>'Taarifa','Status'=>'Hali','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'Njia kali zaidi ya kujiondoa: lolote linalotumwa hapa haliguswi na AI — hakuna uboreshaji, hakuna maelezo ya kuona, hakuna kuandika upya. Kichwa cha chapisho kilichochapishwa, mwili, na manukuu ya kichwa kilichotafsiriwa huchukuliwa kama yalivyo kutoka kwa somo na maandishi ya ujumbe ya msanii; faili lililoambatanishwa/mafayili huchapishwa kama yalivyotumwa. Lango la kukataa kwa ubora hupitishwa, sawa na Photo-only. Tumia kiashiria cha somo [Pure] kama mbadala kwa wateja wa barua pepe wasiounga mkono To: aliases — kwa mfano pure@agnosis.art','Subdomain'=>'Kikoa kidogo','Subject'=>'Somo','Subject line conventions:'=>'Miongozo ya mstari wa mada:','Subject: %s'=>'Somo: %s','Submission discarded'=>'Uwasilishaji umetupiliwa mbali','Submission email password'=>'Nenosiri la barua ya uwasilishaji','Submission limit reached. Please wait before sending again.'=>'Kikomo cha uwasilishaji kimefikiwa. Tafadhali subiri kabla ya kutuma tena.','Submission not found.'=>'Uwasilishaji haujapatikana.','Submit artwork'=>'Wasilisha kazi ya sanaa','Submit biography'=>'Wasilisha wasifu','Submit event'=>'Wasilisha tukio','Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI or Anthropic, depending on this site\'s configuration) to help write publication text and enhance images. If this site instead uses WordPress\'s own built-in AI Client (configured under Settings → Connectors), submitted content is sent to whichever AI service that connector points to instead. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.'=>'Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI or Anthropic, depending on this site\'s configuration) to help write publication text and enhance images. If this site instead uses WordPress\'s own built-in AI Client (configured under Settings → Connectors), submitted content is sent to whichever AI service that connector points to instead. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'Kazi ya sanaa, maandishi, na ujumbe wa mawasiliano wa wageni uliowasilishwa hutumwa kwa %s kwa usindikaji. Unda au chagua ukurasa chini ya Mipangilio → Faragha — programu-jalizi hii tayari imetayarisha maneno yaliyopendekezwa ambayo utayapata hapo chini ya "Mwongozo". Unaweza pia kutaka kukagua makubaliano ya usindikaji wa data (DPA) ya mtoa huduma huyo kwa wajibu wako wa ufuasi.','Submitted text and images may be processed by a third-party AI provider. Approved posts are published publicly and shared across the Fediverse — this cannot be fully undone later.'=>'Maandishi na picha zilizowasilishwa zinaweza kuchakatwa na mtoa huduma wa AI wa nje. Machapisho yaliyoidhinishwa huchapishwa hadharani na kushirikiwa kote katika Fediverse — hili haliwezi kufutwa kikamilifu baadaye.','Subscribe'=>'Jisajili','Subscribe to get these by email'=>'Jisajili upokee hivi kwa barua pepe','Subscribe to the newsletter'=>'Jisajili kwa jarida','Subscribed at'=>'Iliandikishwa tarehe','Subscription confirmed'=>'Usajili umethibitishwa','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'Maneno yaliyopendekezwa yanayohusu %s na ufederishaji wa umma yaliongezwa kwake kiotomatiki — yakague chini ya Mipangilio → Faragha → "Mwongozo" kabla ya kuchapisha, na wasiliana na mtoa huduma wako kuhusu makubaliano yao ya usindikaji wa data (DPA) kwa wajibu wako wa ufuasi.','Supported formats: JPEG, PNG, WebP, GIF, TIFF, or HEIC/HEIF for images; MP3, WAV, M4A, OGG, or FLAC for audio; MP4, MOV, AVI, WebM, OGG, or MPEG for video.'=>'Miundo inayotumika: JPEG, PNG, WebP, GIF, TIFF, au HEIC/HEIF kwa picha; MP3, WAV, M4A, OGG, au FLAC kwa sauti; MP4, MOV, AVI, WebM, OGG, au MPEG kwa video.','Suspend'=>'Simamisha','System prompt'=>'Amri ya mfumo','Tags (comma-separated)'=>'Lebo (zimetenganishwa kwa koma)','Term Translation Cache'=>'Akiba ya Tafsiri za Istilahi','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'Akiba ya tafsiri ya istilahi imefutwa. Istilahi zitatafsiriwa tena zinapohitajika tena.','Test %s'=>'Jaribu %s','Test AI Providers'=>'Jaribu Watoa Huduma wa AI','Test connection'=>'Jaribu muunganisho','Test email sent — check the inbox you sent it to.'=>'Barua pepe ya majaribio imetumwa — angalia kisanduku pokezi ulicholitumia.','Test email sent — check whether it lands in your inbox or your spam folder.'=>'Barua pepe ya majaribio imetumwa — angalia kama inaingia kwenye kisanduku pokezi chako au kwenye folda ya taka.','Test IMAP Connection'=>'Jaribu Muunganisho wa IMAP','Test invitation sent — check the inbox you sent it to.'=>'Mwaliko wa majaribio umetumwa — angalia kisanduku pokezi ulicholitumia.','Text color on the solid accent-colored call-to-action buttons (e.g. "Confirm subscription", "Apply to join"). Change this alongside the accent color above if you pick a light accent that white text wouldn\'t read well against.'=>'Rangi ya maandishi kwenye vitufe thabiti vya wito wa kuchukua hatua vyenye rangi ya lafudhi (km. "Thibitisha usajili", "Omba kujiunga"). Badilisha hii pamoja na rangi ya lafudhi hapo juu ukichagua lafudhi nyepesi ambayo maandishi meupe hayawezi kusomeka vizuri juu yake.','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'Asante kwa kuomba kujiunga na %s. Kwa bahati mbaya, ombi lako halikupata kura za kutosha ndani ya muda wa kupiga kura.','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'Asante kwa kuomba kujiunga na %s. Ombi lako limepokelewa na sasa liko wazi kwa ukaguzi wa jamii.','Thanks for signing up! Confirm your email address to start receiving the newsletter.'=>'Asante kwa kujisajili! Thibitisha anwani yako ya barua pepe ili kuanza kupokea jarida.','Thanks — your message has been sent.'=>'Asante — ujumbe wako umetumwa.','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'Asante — ujumbe wako umetumwa. Unaweza kumfikia msanii huyu tena baada ya muda mfupi.','Thanks, %s!'=>'Asante, %s!','That date could not be understood.'=>'Tarehe hiyo haikuweza kueleweka.','That does not look like a valid link (must start with http:// or https://).'=>'Hiyo haionekani kama kiungo halali (lazima ianze na http:// au https://).','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'Hiyo haionekani kama saa za eneo halali (k.m. "Europe/Madrid").','That doesn\'t look like a valid web address.'=>'Hiyo haionekani kama anwani halali ya wavuti.','That is already the current cap.'=>'Hicho tayari ni kikomo cha sasa.','The %1$s at %2$s is due to send in about a day. Agnosis drafted an intro from what\'s new since the last issue:'=>'%1$s katika %2$s inapaswa kutumwa baada ya takribani siku moja. Agnosis imeandika rasimu ya utangulizi kutoka kwa mambo mapya tangu toleo la mwisho:','The %1$s community has opened a vote to change the membership size cap to %2$s. The vote closes on %3$s.'=>'Jamii ya %1$s imefungua kura ya kubadilisha kikomo cha ukubwa wa uanachama kuwa %2$s. Kura itafungwa tarehe %3$s.','The %1$s community has opened a vote to remove a member. The vote closes on %2$s.'=>'Jamii ya %1$s imefungua kura ya kumwondoa mwanachama. Kura itafungwa tarehe %2$s.','The %s community has admitted you as an artist. Welcome!'=>'Jamii ya %s imekukubali kama msanii. Karibu!','The application by %s has closed without reaching the admission threshold. No action required.'=>'Ombi la %s limefungwa bila kufikia kizingiti cha kukubaliwa. Hakuna hatua inayohitajika.','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'Msanii hakutuma kichwa cha habari wala ujumbe pamoja na uwasilishaji huu — acha picha izungumze kikamilifu yenyewe.','The artist\'s account and all published work have been permanently deleted from %s.'=>'Akaunti ya msanii na kazi zote zilizochapishwa zimefutwa kabisa kutoka %s.','The artwork has been published to the gallery.'=>'Kazi ya sanaa imechapishwa kwenye ghala.','The artwork is photographed at an angle, causing distortion. Shoot straight on, with the camera parallel to the canvas.'=>'Kazi ya sanaa imepigwa picha kwa pembe, na kusababisha upotoshaji. Piga picha moja kwa moja, huku kamera ikiwa sambamba na turubai.','The artwork itself has not been altered — only the photograph quality was corrected.'=>'Kazi ya sanaa yenyewe haijabadilishwa — ubora wa picha pekee ndio umerekebishwa.','The artwork looks distorted or skewed. Position your camera directly in front of the artwork, parallel to its surface.'=>'Kazi ya sanaa inaonekana imepotoshwa au imepinda. Weka kamera yako moja kwa moja mbele ya kazi ya sanaa, sambamba na uso wake.','The cap must be zero or a positive number.'=>'Kikomo lazima kiwe sifuri au nambari chanya.','The community has %d days to vote. We will let you know the outcome by email.'=>'Jamii ina siku %d za kupiga kura. Tutakujulisha matokeo kupitia barua pepe.','The community removal vote has closed with a majority in favor.'=>'Kura ya kuondoa mwanachama wa jamii imefungwa ikiwa na wengi walioidhinisha.','The community removal vote has closed. The required majority was not reached and the artist\'s membership remains active.'=>'Kura ya kuondoa mwanachama wa jamii imefungwa. Wengi unaohitajika haukufikiwa na uanachama wa msanii bado unaendelea.','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'Jumuiya ilipiga kura kubadilisha kikomo cha ukubwa wa uanachama hadi %1$s (pendekezo #%2$d). Kikomo kipya sasa kinaanza kutumika.','The contact form on your page is now turned off.'=>'Fomu ya mawasiliano kwenye ukurasa wako sasa imezimwa.','The event has been published.'=>'Tukio limechapishwa.','The event has been removed.'=>'Tukio limeondolewa.','The following couldn\'t be automatically embedded, so they were left out:'=>'Vifuatavyo havikuweza kupachikwa kiotomatiki, kwa hiyo viliachwa nje:','The full text cannot be empty. Fill it back in, or use "Discard" from the original email instead.'=>'Maandishi kamili hayawezi kuwa tupu. Yajaze tena, au tumia "Tupilia mbali" kutoka kwa barua pepe ya awali badala yake.','The image is blurry. Rest your phone or camera on a stable surface, use the self-timer, and make sure the artwork fills most of the frame so autofocus locks on it.'=>'Picha imefifia. Weka simu au kamera yako juu ya uso thabiti, tumia kipima muda cha kujipiga, na hakikisha kazi ya sanaa inajaza sehemu kubwa ya fremu ili autofocus ifungamane nayo.','The image is out of focus. Tap on the artwork on your phone screen before shooting to make sure autofocus locks on it, and hold the camera still.'=>'Picha haiko kwenye focus. Gusa kazi ya sanaa kwenye skrini ya simu yako kabla ya kupiga picha ili kuhakikisha autofocus inafungamana nayo, na ushikilie kamera bila kusogea.','The image is pixelated. Shoot from closer or use a higher resolution setting on your camera.'=>'Picha ina vizuizi vya pikseli. Piga kutoka karibu zaidi au tumia mpangilio wa uazimio wa juu zaidi kwenye kamera yako.','The image resolution is too low. Use your phone\'s highest quality setting and fill the frame with the artwork.'=>'Uazimio wa picha ni mdogo sana. Tumia mpangilio wa ubora wa juu zaidi kwenye simu yako na ijaze fremu kwa kazi ya sanaa.','The image resolution is too low. Use your phone\'s highest quality setting and make sure you\'re close enough that the artwork fills the frame.'=>'Uazimio wa picha ni mdogo sana. Tumia mpangilio wa ubora wa juu zaidi kwenye simu yako na hakikisha uko karibu vya kutosha ili kazi ya sanaa ijaze fremu.','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'Fomu ya maombi ya Jiunge na fomu ya Kujisajili kwa Jarida zote zinahitaji uthibitishaji wa kibinadamu kabla ya kukubali uwasilishaji.','The original published item could not be found.'=>'Kipengee cha awali kilichochapishwa hakikuweza kupatikana.','The overall photo quality was too low for our AI to process the artwork clearly.'=>'Ubora wa jumla wa picha ulikuwa mdogo sana kwa AI yetu kuchakata kazi ya sanaa kwa uwazi.','The photo has a cold blue tint. Move the artwork to a warmer, more natural light source or adjust your camera\'s white balance.'=>'Picha ina kivuli cha buluu baridi. Hamisha kazi ya sanaa hadi kwenye chanzo cha mwanga chenye joto zaidi na cha asili zaidi au rekebisha white balance ya kamera yako.','The photo has a strong color cast. Shoot under neutral daylight or use your phone\'s Auto White Balance setting for more accurate colors.'=>'Picha ina mabadiliko makubwa ya rangi. Piga chini ya mwanga wa asili usio na rangi au tumia mpangilio wa Auto White Balance wa simu yako kwa rangi zilizo sahihi zaidi.','The photo is overexposed (too bright / washed out). Avoid direct sunlight or flash pointed straight at the artwork — diffuse or indirect light works best.'=>'Picha imepigwa kwa mwanga mwingi kupita kiasi (ni ang’avu sana / imefutika). Epuka jua la moja kwa moja au flash iliyolengwa moja kwa moja kwenye kazi ya sanaa — mwanga ulioenezwa au usio wa moja kwa moja hufanya kazi vizuri zaidi.','The photo is too bright or washed out. Avoid direct sunlight or flash — diffuse light or shade gives more even tones.'=>'Picha ni ang’avu sana au imefutika. Epuka jua la moja kwa moja au flash — mwanga uliotawanyika au kivuli hutoa tani zilizo sawa zaidi.','The photo is too dark to show your artwork clearly. Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'Picha ni nyeusi sana kiasi kwamba haiwezi kuonyesha kazi yako ya sanaa kwa uwazi. Jaribu kupiga picha karibu na dirisha kubwa wakati wa mchana, au tumia taa laini ukiielekeza kwenye kazi kutoka upande.','The photo is underexposed (too dark). Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'Picha imepigwa kwa mwanga hafifu sana (ni nyeusi kupita kiasi). Jaribu kupiga picha karibu na dirisha kubwa wakati wa mchana, au tumia taa laini ukiielekeza kwenye kazi kutoka upande.','The photo looks too yellow or warm. Shoot under natural daylight or switch your phone\'s white balance to Daylight / Cloudy.'=>'Picha inaonekana ya manjano sana au ya joto kupita kiasi. Piga chini ya mwanga wa asili wa mchana au badilisha white balance ya simu yako kuwa Daylight / Cloudy.','The Publish and Discard links above expire in %d day. Your submission stays as a draft until you decide.'=>'Viungo vya Chapisha na Tupa vilivyo hapo juu vinaisha baada ya siku %d moja. Uwasilishaji wako unabaki kama rasimu mpaka uamue.' . "\0" . 'Viungo vya Chapisha na Tupa vilivyo hapo juu vinaisha baada ya siku %d. Uwasilishaji wako unabaki kama rasimu mpaka uamue.','The removal link has expired. Please send another removal request.'=>'Kiungo cha uondoaji kimeisha muda wake. Tafadhali tuma ombi jingine la uondoaji.','The submission has been discarded.'=>'Uwasilishaji umetupiliwa mbali.','The title cannot be empty.'=>'Kichwa hakiwezi kuwa tupu.','The uploaded file could not be read.'=>'Faili iliyopakiwa haikuweza kusomwa.','Their account and all published work have been permanently deleted.'=>'Akaunti yao na kazi zote zilizochapishwa zimefutwa kabisa.','There is a reflection on the artwork surface. Tilt the canvas slightly or change your angle to eliminate it.'=>'Kuna mwanga unaoakisiwa kwenye uso wa kazi ya sanaa. Pindua turubai kidogo au badilisha pembe yako ili kuuondoa.','There is a shadow across part of the artwork. Reposition your light source or move the artwork so no shadows fall on the surface.'=>'Kuna kivuli kinachopita juu ya sehemu ya kazi ya sanaa. Rekebisha tena chanzo chako cha mwanga au isogeze kazi ya sanaa ili hakuna vivuli vinavyotua juu ya uso.','There is glare or a bright reflection on the artwork. Tilt the canvas slightly or photograph at an angle to eliminate reflections from the surface.'=>'Kuna mng’ao au miale ya mwanga mkali kwenye kazi ya sanaa. Pindua turubai kidogo au piga picha kwa pembe ili kuondoa mwangaza unaoakisiwa kutoka kwenye uso.','There is motion blur. Hold the camera very still or use a tripod; press the shutter gently or use the self-timer to avoid shake.'=>'Kuna ukungu wa mwendo. Shikilia kamera bila kusogea kabisa au tumia tripod; bonyeza shutter kwa upole au tumia kipima muda cha kujipiga ili kuepuka mtikisiko.','There is no photo to restore.'=>'Hakuna picha ya kurejesha.','These confirmation links expire in 7 days.'=>'Viungo hivi vya uthibitisho vinaisha muda baada ya siku 7.','These fields save without any preview — the first real look at how your colors, width, and logo combine is otherwise whatever email happens to go out next. Send yourself a sample using the settings currently saved above (save first if you just changed something and want the test to match).'=>'Sehemu hizi huhifadhiwa bila hakikisho lolote — mwonekano wa kwanza halisi wa jinsi rangi zako, upana, na nembo vinavyoungana vinginevyo ni barua pepe yoyote itakayotumwa ijayo. Jitumie sampuli ukitumia mipangilio iliyohifadhiwa hapo juu (hifadhi kwanza ikiwa umebadilisha kitu na unataka jaribio lifanane).','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'Anwani hii imevurugika au imeripotiwa kama barua taka — huenda barua hazifiki tena kwa msanii huyu.','This artist can\'t be reached through this form right now.'=>'Msanii huyu hawezi kufikiwa kupitia fomu hii kwa sasa.','This artist has muted community broadcast messages.'=>'Msanii huyu amenyamazisha jumbe za matangazo za jumuiya.','This artist receives one daily digest of open applications instead of an email per application.'=>'Msanii huyu hupokea muhtasari mmoja wa kila siku wa maombi yaliyo wazi badala ya barua pepe kwa kila ombi.','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'Jamii hii imejaa kwa sasa, kwa hiyo ombi lako limeingizwa kwenye orodha ya kusubiri — mwanajamii akiondoka, mtu anayefuata kwenye foleni anaingizwa.','This confirmation link expires in 7 days.'=>'Kiungo hiki cha uthibitisho muda wake unaisha baada ya siku 7.','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'Kiungo hiki cha uthibitisho tayari kimetumiwa au si halali tena. Ikiwa bado unataka kuondoka, tafadhali omba uondoaji tena kutoka kwenye akaunti yako.','This confirmation link is invalid or has already been used.'=>'Kiungo hiki cha uthibitisho si sahihi au tayari kimetumiwa.','This confirms that your account and everything you published on %s have been permanently deleted, as you requested.'=>'Hii inathibitisha kwamba akaunti yako na kila kitu ulichochapisha kwenye %s kimefutwa kabisa, kama ulivyoomba.','This conflicts with Agnosis artist subdomains — both plugins would claim the same subdomain namespace.'=>'Hii inakinzana na vikoa vidogo vya wasanii vya Agnosis — programu-jalizi zote mbili zingedai nafasi ile ile ya kikoa kidogo.','This email address belongs to an admitted artist.'=>'Anwani hii ya barua pepe ni ya msanii aliyekubaliwa.','This field cannot be edited here.'=>'Sehemu hii haiwezi kuhaririwa hapa.','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'Huu ni jaribio la mara moja la uwasilishaji kutoka kwa ukurasa wako wa Agnosis Settings → Email Inbox. Ikiwa unasoma hili kwenye kisanduku chako cha barua (si taka), utambulisho wa From wa jamii/miamala unaweza kuwasilishwa kwa anwani hii.','This is a sample of the branded email shell — header, body text, a button, and (below) the footer card — built from whatever is currently saved on Settings → Branding.'=>'Huu ni sampuli ya ganda la barua pepe lenye chapa — kichwa, maandishi ya mwili, kitufe, na (chini) kadi ya kijachini — iliyojengwa kutokana na kilichohifadhiwa sasa katika Mipangilio → Chapa.','This is a TEST send — it previews the next issue using the current draft intro and recent activity. It was not counted as a real send and no subscribers were emailed. The unsubscribe link below is a non-functional placeholder.'=>'Hii ni utumaji wa JARIBIO — unaonyesha toleo lijalo kwa kutumia utangulizi wa rasimu ya sasa na shughuli za hivi karibuni. Haikuhesabiwa kama utumaji wa kweli na hakuna wasajili waliotumiwa barua pepe. Kiungo cha kujiondoa hapa chini ni kishikio kisichofanya kazi.','This is the LinguaForge default and allows artist subdomains to coexist with language subfolders'=>'Hii ndiyo chaguo-msingi ya LinguaForge na huruhusu vikoa vidogo vya wasanii kuwepo pamoja na vifolderi vya lugha','This link may have already been used or may have expired. Please log in to manage your submissions.'=>'Huenda kiungo hiki tayari kimetumiwa au muda wake umekwisha. Tafadhali ingia ili kusimamia uwasilishaji wako.','This message was sent by %s.'=>'Ujumbe huu ulitumwa na %s.','This newsletter issue could not be found.'=>'Toleo hili la jarida halikuweza kupatikana.','This node couldn\'t safely load that page to review it (it may be unreachable, or blocked for security reasons).'=>'Nodi hii haikuweza kupakia ukurasa huo kwa usalama ili kuukagua (huenda haupatikani, au umezuiwa kwa sababu za usalama).','This page is not in your own language. Edit the version in your language instead.'=>'Ukurasa huu hauko katika lugha yako mwenyewe. Hariri toleo katika lugha yako badala yake.','This preferences link is invalid or has been tampered with.'=>'Kiungo hiki cha mapendeleo si halali au kimebadilishwa.','This preferences link is no longer valid for this account.'=>'Kiungo hiki cha mapendeleo si halali tena kwa akaunti hii.','This review link has expired. Please log in to manage your submissions.'=>'Kiungo hiki cha ukaguzi kimekwisha muda wake. Tafadhali ingia ili kusimamia uwasilishaji wako.','This site isn\'t on this Agnosis node\'s list of trusted platforms, and automatic link review is turned off here.'=>'Tovuti hii haiko kwenye orodha ya mifumo inayoaminika ya nodi hii ya Agnosis, na ukaguzi wa kiotomatiki wa viungo umezimwa hapa.','This submission is not awaiting review.'=>'Uwasilishaji huu haujasubiri ukaguzi.','This unsubscribe link is invalid or has already been used.'=>'Kiungo hiki cha kujiondoa si halali au tayari kimetumika.','This unsubscribe link is invalid or has been tampered with.'=>'Kiungo hiki cha kujiondoa si halali au kimechezewa.','This vote is not currently open.'=>'Kura hii kwa sasa haijafunguliwa.','This vote link is invalid or has been tampered with.'=>'Kiungo hiki cha kura si sahihi au kimehaririwa kwa njia isiyo halali.','This webhook request has already been processed.'=>'Ombi hili la webhook tayari limechakatwa.','This will permanently discard the submission — it will not be published.'=>'Hili litatupilia mbali kabisa uwasilishaji — halitachapishwa.','This will remove the published artwork from the gallery.'=>'Hili litaondoa kazi ya sanaa iliyochapishwa kutoka kwenye ghala.','Thumbnail size (px)'=>'Ukubwa wa kijipicha (px)','Time'=>'Muda','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'Dirisha la muda, kwa saa, ambalo kikomo cha mawasiliano kwa kila msanii hapo juu kinatumika. Pia hudhibiti muda ambao mgeni huona ilani ya "tayari umewasiliana" badala ya fomu baada ya kumwandikia msanii. Chaguo-msingi: 1 (saa moja).','Timezone'=>'Saa za eneo','Title'=>'Kichwa','Title and full text cannot be empty. Fill them back in, or use "Discard" from the original email instead.'=>'Kichwa na maandishi kamili haviwezi kuwa tupu. Yajaze tena, au tumia "Tupilia mbali" kutoka kwa barua pepe ya awali badala yake.','Titles are matched exactly, so a small difference in wording is enough to miss — double-check spelling, capitalization, and punctuation against the list above before resending.'=>'Vichwa vinalinganishwa kwa usahihi kamili, hivyo tofauti ndogo tu katika maneno inatosha kukosa — angalia tena tahajia, herufi kubwa, na alama za uakifishaji dhidi ya orodha iliyo hapo juu kabla ya kutuma tena.','To leave the network and delete your account:'=>'Kuondoka kwenye mtandao na kufuta akaunti yako:','To resend correctly:'=>'Ili kutuma tena kwa usahihi:','Too many requests. Please wait %d seconds and try again.'=>'Maombi mengi sana. Tafadhali subiri sekunde %d kisha ujaribu tena.','Top'=>'Juu','Transaction (donation/sale) records were kept in full — financial records are subject to a legal retention obligation and are exempt from erasure under GDPR Art. 17(3)(b).'=>'Rekodi za miamala (michango/uuzaji) zilihifadhiwa kikamilifu — rekodi za kifedha ziko chini ya wajibu wa kisheria wa kuhifadhiwa na hazina msamaha wa kufutwa chini ya GDPR Art. 17(3)(b).','Transaction fee (%)'=>'Ada ya muamala (%)','Translated message'=>'Ujumbe uliotafsiriwa','Trigger icon'=>'Ikoni ya kichochezi','Trust all admitted artists (skip link review entirely)'=>'Waamini wasanii wote waliokubaliwa (ruka ukaguzi wa kiungo kabisa)','Trusted embed platforms'=>'Majukwaa ya kupachika yaliyoaminika','Turn off the contact form on my page — visitors won\'t be able to message me.'=>'Zima fomu ya mawasiliano kwenye ukurasa wangu — wageni hawataweza kunitumia ujumbe.','Turnstile is configured.'=>'Turnstile imesanidiwa.','Turnstile is not configured.'=>'Turnstile haijasasidiwa.','Type'=>'Aina','Uli Hake'=>'Uli Hake','Unavailable on this host'=>'Haipatikani kwenye mwenyeji huyu','Unknown'=>'Haijulikani','Unknown newsletter type.'=>'Aina ya jarida isiyojulikana.','Unknown provider.'=>'Mtoa huduma hajulikani.','unregistered sender'=>'mtumaji asiyejisajili','Unsubscribe'=>'Jiondoe','Unsubscribe from the newsletter?'=>'Ungependa kujiondoa kwenye jarida?','Unsubscribed'=>'Umejiondoa','Unsubscribed at'=>'Iliotolewa usajili tarehe','Unsupported field target.'=>'Lengo la sehemu halitumiki.','until this is resolved.'=>'mpaka hili litatatuliwa.','Untitled'=>'Bila kichwa','Upcoming events'=>'Matukio yanayokuja','Update Medium'=>'Sasisha Kati','Update your artist biography.'=>'Sasisha wasifu wako wa msanii.','Uploading…'=>'Inapakiwa…','Use natural light — position the artwork near a window on a cloudy day for even, soft light.'=>'Tumia mwanga wa asili — weka kazi ya sanaa karibu na dirisha siku ya mawingu kwa mwanga laini na sawa.','Use SSL'=>'Tumia SSL','Use your mail app\'s "Attach file" (usually a paperclip icon) rather than "Insert photo" or pasting the image directly into the message body.'=>'Tumia "Ambatisha faili" ya programu yako ya barua (kwa kawaida ikoni ya klipu ya karatasi) badala ya "Ingiza picha" au kubandika picha moja kwa moja kwenye sehemu ya ujumbe.','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'Ujumbe wa mtumiaji unaotumwa pamoja na picha ya kazi ya sanaa. Tumia {artist_prompt} ambapo maelezo ya msanii mwenyewe yanapaswa kuonekana.','Username or email address'=>'Jina la mtumiaji au anwani ya barua pepe','Verification failed. Please try again.'=>'Uthibitishaji umefeli. Tafadhali jaribu tena.','View Agnosis details'=>'Tazama maelezo ya Agnosis','View Artwork'=>'Tazama Kazi ya Sanaa','View Biography'=>'Tazama Wasifu','View details'=>'Tazama maelezo','View Event'=>'Tazama Tukio','View it live'=>'Ione moja kwa moja','View it online.'=>'Ione mtandaoni.','View Post'=>'Tazama Chapisho','View submissions →'=>'Tazama uwasilishaji →','Vision image max width (px)'=>'Upana wa juu wa picha ya kuona (px)','Visit plugin site'=>'Tembelea tovuti ya programu-jalizi','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'Ujumbe wa mawasiliano kati ya mgeni na msanii (uliotumwa au uliokataliwa) uliozidi muda huu hufutwa kabisa na usafishaji wa kila siku. Anwani ya IP ya mgeni husafishwa kando baada ya siku 30 bila kujali mpangilio huu, mara unapokuwa hauna tena faida kwa uchunguzi wa matumizi mabaya. Chaguo-msingi: siku 90.','Visitors can still reach you through the contact form on your page.'=>'Wageni bado wanaweza kukufikia kupitia fomu ya mawasiliano kwenye ukurasa wako.','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'Wageni hujisajili kupitia kizuizi cha agnosis/newsletter-signup (uthibitisho wa mara mbili). Digest: kazi mpya za sanaa na matukio yaliyochapishwa tangu toleo la mwisho.','Vote'=>'Kura','Vote against this application?'=>'Kupiga kura dhidi ya ombi hili?','Vote error'=>'Hitilafu ya kura','Vote in favor of this application?'=>'Kupiga kura kuunga mkono ombi hili?','Vote NO'=>'Piga kura HAPANA','Vote NO (keep)'=>'Piga kura HAPANA (hifadhi)','Vote recorded'=>'Kura imerekodiwa','Vote to keep this artist in the community?'=>'Kupiga kura ili kumwacha msanii huyu abaki kwenye jamii?','Vote to remove this artist from the community?'=>'Kupiga kura ili kumwondoa msanii huyu kwenye jamii?','Vote YES'=>'Piga kura NDIYO','Vote YES (remove)'=>'Piga kura NDIO (ondoa)','Voter account not found.'=>'Akaunti ya mpiga kura haikupatikana.','Votes'=>'Kura','Voting window (days)'=>'Dirisha la kura (siku)','Voting window: %d day(s).'=>'Dirisha la kupiga kura: siku %d.','Vouch messages you wrote were redacted. Governance votes you cast were kept as-is — a vote is a community record, not personal data, and removing it would silently change a settled decision.'=>'Ujumbe wa vouch ulioandika ulifichuliwa. Kura za utawala ulizopiga zilihifadhiwa jinsi zilivyo — kura ni rekodi ya jamii, si data binafsi, na kuiondoa kungebadilisha kimya kimya uamuzi uliokwisha fikiwa.','Want to tweak the title, text or tags before publishing?'=>'Unataka kurekebisha kichwa, maandishi au lebo kabla ya kuchapisha?','We detected some photographic issues and applied AI correction to improve visibility of your artwork:'=>'Tuligundua baadhi ya matatizo ya picha na tumetumia marekebisho ya AI kuboresha mwonekano wa kazi yako ya sanaa:','We received a removal request for "%s", but couldn\'t find an artwork or event with that exact title in your account.'=>'Tulipokea ombi la kuondoa "%s", lakini hatukuweza kupata kazi ya sanaa au tukio lenye kichwa hicho hicho kabisa katika akaunti yako.','We received a removal request for the following %s:'=>'Tulipokea ombi la kuondoa %s ifuatayo:','We received a removal request, but more than one of your posts shares that exact title. Choose which one you meant below — each is independent, so removing one leaves the others untouched.'=>'Tulipokea ombi la kuondoa, lakini zaidi ya chapisho moja lako lina kichwa hicho hasa. Chagua lipi ulimaanisha hapa chini — kila moja ni huru, kwa hivyo kuondoa moja kunaacha mengine bila kuguswa.','We received a request to feature "%s", but couldn\'t find a published artwork with that exact title in your account.'=>'Tulipokea ombi la kuangazia "%s", lakini hatukuweza kupata kazi ya sanaa iliyochapishwa yenye kichwa hicho hicho kabisa katika akaunti yako.','We received a request to remove your account and all your published work from %s.'=>'Tulipokea ombi la kuondoa akaunti yako na kazi zako zote ulizochapisha kutoka %s.','We received your application to %s'=>'Tumepokea ombi lako kwa %s','We received your email, but couldn\'t process a usable photo, audio, or video file from it — so nothing was published. This can happen when an image is pasted or inserted inline rather than added as a proper attachment, or when a file arrives in a format this server can\'t convert (for example, an iPhone photo saved in HEIC/HEIF format).'=>'Tulipokea barua pepe yako, lakini hatukuweza kuchakata faili ya picha, sauti, au video inayoweza kutumika kutoka humo — kwa hiyo hakuna kilichochapishwa. Hii inaweza kutokea picha inapobandikwa au kuingizwa ndani ya ujumbe badala ya kuambatishwa ipasavyo, au faili inapofika katika umbizo ambalo seva hii haiwezi kubadilisha (kwa mfano, picha ya iPhone iliyohifadhiwa katika umbizo la HEIC/HEIF).','We received your email, but it looked like a reply or a forwarded message — carrying quoted text from an earlier email. We looked for your own original text or an attachment above the quoted part, but couldn\'t find anything to work with, so nothing was published.'=>'Tulipokea barua pepe yako, lakini ilionekana kama jibu au ujumbe uliotumwa mbele — ikiwa na maandishi yaliyotajwa moja kwa moja kutoka kwa barua pepe ya awali. Tulitafuta maandishi yako ya asili au kiambatisho juu ya sehemu iliyotajwa, lakini hatukupata chochote cha kufanyia kazi, kwa hiyo hakuna kilichochapishwa.','We received your submission, but unfortunately the photo quality is too low for us to show your artwork clearly. We didn\'t publish it — but please don\'t be discouraged! A simple retake is usually all it takes.'=>'Tumepokea uwasilishaji wako, lakini kwa bahati mbaya ubora wa picha ni mdogo sana kiasi kwamba hatuwezi kuonyesha kazi yako ya sanaa kwa uwazi. Hatukuiweka — lakini tafadhali usivunjike moyo! Kupiga tena picha mara moja kwa kawaida kunatosha.','Webhook request timestamp is missing, malformed, or too old.'=>'Muhuri wa muda wa ombi la webhook haupo, umeharibika, au ni wa zamani sana.','Webhook secret'=>'Siri ya webhook','Webhook secret not configured.'=>'Siri ya webhook haijasanidiwa.','Welcome to %s'=>'Karibu kwenye %s','Welcome to our newest member: %s'=>'Karibu mwanachama wetu mpya zaidi: %s' . "\0" . 'Karibu wanachama wetu wapya zaidi: %s','What personal data we collect and why'=>'Tunaokusanya data gani binafsi na kwa nini','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'Ikitumika, kiungo cha tovuti ambacho hakiko kwenye orodha iliyoaminika hapo juu hakitupwi tu: ukurasa wa lengwa hufutwa na kukaguliwa na mtoa huduma wako wa AI uliosanidiwa (Mipangilio → Watoa Huduma wa AI) dhidi ya kategoria zilizo hapa chini kabla ya kuamua kama kiingizwe. Ikiwa AI haipatikani, ombi huisha muda wake, au ukurasa hauwezi kufutwa kwa usalama, kiungo hakipachikwi — hufeli kwa usalama. Ikitoshelezwa (chaguo-msingi), ni majukwaa yaliyoaminika hapo juu pekee yanayowahi kupachikwa.','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'Wakati kimewezeshwa, Agnosis hutengeneza rasimu ya utangulizi kwa kutumia AI kabla ya kila toleo (angalia muda wa kuongoza hapa chini), huihifadhi kwenye uga wa utangulizi wa jarida hilo, na hukutumia barua pepe ili uikague — isipokuwa kama tayari umeandika moja kwa mzunguko huo. Lemaza ili kuacha uga wote wa utangulizi kama ulivyoziacha, daima.','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Ikitumika, uwasilishaji wa wasifu hupitishwa kupitia AI ili kusahihisha tahajia na kufanya maboresho madogo ya maandishi kabla ya kuhifadhiwa.','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'Ikitumika, masasisho ya wasifu huunganishwa na wasifu uliopo kwa kutumia AI — taarifa mpya huingizwa badala ya kubadilisha kila kitu. Inapendekezwa: wasanii wanaweza kutuma masasisho ya nyongeza ("Nimeshinda tuzo hivi punde") bila kutuma upya wasifu wao kamili. Zima ili kila wakati ubadilishe wasifu na uwasilishaji wa hivi karibuni.','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'Ikitumika, uwasilishaji wa matukio hupitishwa kupitia AI ili kusahihisha tahajia na kufanya maboresho madogo ya maandishi kabla ya kuhifadhiwa.','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'Ikiwashwa, ujumbe wa ingizo lazima upitishe uthibitishaji wa SPF au DKIM (kupitia kichwa cha Authentication-Results). Huzuia anwani za From: zilizoghushiwa. Inahitaji ESP yako ijumuishe vichwa vya Authentication-Results na kikoa chako kiwe na rekodi za SPF/DKIM zilizosetiwa. Acha ikiwa huna uhakika — barua halali ikikataliwa huwa kimyakimya. Chaguo-msingi: imezimwa.','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'Inapowekwa, kila ukurasa wa wasifu wa msanii hutumia kichwa hiki hasa badala ya chake mwenyewe, bila kujali msanii aliwasilisha nini, alihariri nini kwenye fomu yake ya kuidhinishwa, au alibadilisha nini baadaye kwenye ukurasa wake uliochapishwa. Acha wazi ili kuendelea kutumia kichwa cha kila msanii mwenyewe (chaguo-msingi). Huonyeshwa hasa kama kilivyoandikwa hapa katika kila toleo la lugha la ukurasa wa wasifu — hakitatafsiriwa kiotomatiki kwa kila lugha. Tazama "Jumuisha jina la msanii kwenye kichwa kilichowekwa awali" hapa chini.','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'Wakati kichwa kilichowekwa awali hapo juu kimewekwa, ongeza jina la onyesho la WordPress la msanii mwenyewe mwishoni mwake (kwa mfano, "Kutana na Msanii — Jane Doe"). Haina athari wakati kichwa kilichowekwa awali kiko wazi.','When you apply to join, we store your email address, display name, biography, statement, and portfolio link to run the community vouching process. When you email us artwork, a biography, or an event, the content of that email (including your address) is stored while it is processed and reviewed. When you subscribe to our newsletter or message an artist through their contact form, we store your email address (and, for contact messages, your IP address) to deliver that message or send you future issues.'=>'Unapotuma ombi la kujiunga, tunahifadhi anwani yako ya barua pepe, jina la kuonyesha, wasifu, taarifa, na kiungo cha jalada la kazi ili kuendesha mchakato wa uthibitishaji wa jamii. Unapotutumia kazi ya sanaa, wasifu, au tukio kwa barua pepe, maudhui ya barua hiyo (ikiwemo anwani yako) huhifadhiwa wakati yanashughulikiwa na kukaguliwa. Unapojiandikisha kwa jarida letu au kumwandikia msanii kupitia fomu yake ya mawasiliano, tunahifadhi anwani yako ya barua pepe (na, kwa ujumbe wa mawasiliano, anwani yako ya IP) ili kuwasilisha ujumbe huo au kukutumia matoleo ya baadaye.','Who we share it with'=>'Tunashiriki na nani','Why do you want to join?'=>'Kwa nini unataka kujiunga?','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'Upana wa ukubwa wa agnosis-artwork unaotumika katika maudhui ya chapisho na lightbox. Urefu huongezeka sawia. Chaguo-msingi: 1920. Picha zilizopo zinahitaji kuzalishwa upya baada ya kubadilisha thamani hii.','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'Upana wa ukubwa wa agnosis-email unaotumika katika barua pepe za arifa za msanii. Urefu huongezeka sawia — hakuna ukataji. Chaguo-msingi: 420. Picha zilizopo zinahitaji kuzalishwa upya baada ya kubadilisha thamani hii.','Width of the card every outgoing HTML email is built around. 600px is the long-standing email-safe default most clients render reliably — narrower reads awkwardly on desktop, wider risks getting clipped or horizontally scrolled by some mobile mail apps. Default: 600.'=>'Upana wa kadi ambayo kila barua pepe ya HTML inayotumwa nje hujengwa juu yake. 600px ni chaguo chaguomsingi la muda mrefu linalofaa barua pepe ambalo wateja wengi huonyesha kwa uaminifu — nyembamba zaidi husomwa kwa shida kwenye kompyuta, pana zaidi huenda ikakatwa au kulazimika kusogeza mlalo kwenye baadhi ya programu za barua pepe za simu. Chaguo msingi: 600.','WordPress AI Client'=>'Mteja wa AI wa WordPress','WordPress AI Client is available and a text-generation model is configured.'=>'Mteja wa AI wa WordPress unapatikana na modeli ya kuzalisha maandishi imesanidiwa.','WordPress AI Client requires WordPress 7.0 or later.'=>'Mteja wa AI wa WordPress unahitaji WordPress 7.0 au toleo la baadaye.','wp_mail() reported a failure — check your site\'s outgoing mail configuration.'=>'wp_mail() imeripoti hitilafu — angalia usanidi wa barua pepe zinazoondoka wa tovuti yako.','Write about this artwork…'=>'Andika kuhusu kazi hii ya sanaa…','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'Huandika dampo ghafi za uchunguzi wa bomba la kupokea barua pepe (muundo wa ujumbe, utambuzi wa MIME wa viambatisho, ubadilishaji wa media, uundaji wa chapisho) kwenye saraka maalumu ya utatuzi — kina chake ni kikubwa zaidi kuliko kile ambacho kichupo cha Rekodi huhifadhi, kwa kufuatilia hasa mahali ambapo uwasilishaji ulikataliwa au kupotea. Zima ukishapata unachohitaji; faili zinaweza kujilimbikiza haraka. Pia inaweza kulazimishwa kutoka wp-config.php kwa `define( \'AGNOSIS_DEBUG\', true );`, ambayo hubatilisha chaguo hili la kuwasha/kuzima. Tazama kidirisha cha Faili za Utatuzi hapa chini kwa eneo la saraka na kitufe cha kufuta faili zote.','Yes, discard it'=>'Ndiyo, litupilie mbali','Yes, remove it'=>'Ndiyo, iondoe','Yes, remove this %s'=>'Ndiyo, ondoa %s hii','Yes, remove this instead'=>'Ndiyo, ondoa hili badala yake','You are already an admitted Agnosis artist.'=>'Tayari wewe ni msanii aliyekubaliwa wa Agnosis.','You are welcome to apply again in the future.'=>'Unakaribishwa kuomba tena baadaye.','You can change your vote at any time within the voting window.'=>'Unaweza kubadilisha kura yako wakati wowote ndani ya muda wa kupiga kura.','You cannot nominate yourself for removal.'=>'Huwezi kujiteua kwa ajili ya kuondolewa.','You cannot vote on your own application.'=>'Huwezi kupiga kura kwenye ombi lako mwenyewe.','You cannot vote on your own removal.'=>'Huwezi kupiga kura kuhusu kuondolewa kwako mwenyewe.','You do not have permission to perform this action.'=>'Huna ruhusa ya kutekeleza kitendo hiki.','You do not have permission to review this submission.'=>'Huna ruhusa ya kukagua uwasilishaji huu.','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'Una wasajili wa umma waliothibitishwa %1$d, juu ya kizingiti cha faraja kilichosanidiwa cha %2$d. Ujumbe unaotumwa mwenyewe bado unafanya kazi, lakini huenda ukataka kuunganisha mtoa huduma wa barua pepe (kwa mfano, ngazi ya bure ya Brevo) kwa uwasilishaji bora zaidi kwa kiwango hiki.','You have left'=>'Umeondoka','You may only edit your own content.'=>'Unaweza kuhariri maudhui yako mwenyewe pekee.','You must be logged in.'=>'Lazima uwe umeingia.','You voted against this application.'=>'Ulipiga kura dhidi ya ombi hili.','You voted in favor of this application.'=>'Ulipiga kura kuunga mkono ombi hili.','You voted to keep this artist in the community.'=>'Ulipiga kura kumwacha msanii huyu kwenye jamii.','You voted to remove this artist from the community.'=>'Ulipiga kura kuondoa msanii huyu kutoka kwenye jamii.','You will be automatically reinstated on that date.'=>'Utarejeshwa kiotomatiki tarehe hiyo.','You will no longer receive the artist newsletter. You can re-subscribe any time from your submissions page.'=>'Hutapokea tena jarida la wasanii. Unaweza kujisajili tena wakati wowote kutoka kwenye ukurasa wako wa mawasilisho.','You will no longer receive the newsletter. Sorry to see you go.'=>'Hutapokea tena jarida. Tunasikitika kukuona unaondoka.','You will stop receiving the newsletter once you confirm below.'=>'Utaacha kupokea jarida mara tu utakapothibitisha hapa chini.','You\'ll continue to receive community broadcasts.'=>'Utaendelea kupokea matangazo ya jumuiya.','You\'ll receive an email as soon as each new application arrives.'=>'Utapokea barua pepe mara tu kila ombi jipya litakapowasili.','You\'ll receive one daily digest of applications awaiting your vote.'=>'Utapokea muhtasari mmoja wa kila siku wa maombi yanayosubiri kura yako.','You\'ll start receiving the newsletter once you confirm below.'=>'Utaanza kupokea jarida mara tu utakapothibitisha hapa chini.','You\'re all set — the community can now review your application and vote.'=>'Umefikia — sasa jamii inaweza kukagua ombi lako na kupiga kura.','You\'re all set — the newsletter will land in your inbox from now on.'=>'Sasa kila kitu kiko sawa — jarida litaanza kuingia kwenye kikasha chako kuanzia sasa.','You\'re invited'=>'Umealikwa','You\'re invited to join %s'=>'Umealikwa kujiunga na %s','You\'ve left %s'=>'Umeondoka %s','you@example.com'=>'you@example.com','Your %s has been removed.'=>'%s yako imeondolewa.','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'Akaunti yako na kila kitu ulichochapisha kwenye %s vimefutwa kabisa. Hakuna chochote kinachohusiana nawe kinachohifadhiwa hapa tena.','Your application to %s'=>'Ombi lako kwa %s','Your application will open for community review once you confirm below.'=>'Ombi lako litafunguliwa kwa ukaguzi wa jamii mara tu utakapothibitisha hapa chini.','Your artwork has been removed from the gallery.'=>'Kazi yako ya sanaa imeondolewa kwenye ghala.','Your biography has been published.'=>'Wasifu wako umechapishwa.','Your biography has been removed.'=>'Wasifu wako umeondolewa.','Your biography, statement, and portfolio link were erased. Your email address was kept on file — your account is currently banned, and it\'s the only way this site can continue to enforce that.'=>'Wasifu wako, taarifa, na kiungo cha jalada la kazi vilifutwa. Anwani yako ya barua pepe ilibaki kwenye kumbukumbu — akaunti yako kwa sasa imepigwa marufuku, na hicho ndicho kigezo pekee kinachoruhusu tovuti hii kuendelea kutekeleza hilo.','Your current titles:'=>'Vichwa vyako vya sasa:','Your email address'=>'Anwani yako ya barua pepe','Your gallery:'=>'Matunzio yako:','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'Fomu yako ya maombi ya Jiunge ni ya umma — mtu yeyote anaweza kuwasilisha ombi, na ombi lililowasilishwa (na kuthibitishwa) bado hutuma barua pepe kwa kila msanii aliyeidhinishwa na msimamizi. Kwa sasa, kitu pekee kinachosimama kati ya fomu hiyo na roboti otomatiki ni kikomo kisichobadilika cha mawasilisho 5 kwa dakika kwa kila IP, ambacho roboti iliyosambazwa inaweza kukiepuka kabisa. Ongeza ufunguo wa tovuti wa Cloudflare Turnstile na ufunguo wa siri hapo juu ili kuhitaji uthibitishaji wa kibinadamu kwenye fomu ya Jiunge na fomu ya Kujisajili kwa Jarida.','Your membership application/account is still active. To remove this data, use the "leave the network" link from any Agnosis email, or ask an administrator.'=>'Ombi lako la uanachama/akaunti bado linafanya kazi. Ili kuondoa data hii, tumia kiungo cha "ondoka kwenye mtandao" kutoka kwa barua yoyote ya Agnosis, au muulize msimamizi.','Your membership at %1$s has been temporarily suspended until %2$s.'=>'Uanachama wako katika %1$s umesitishwa kwa muda hadi %2$s.','Your membership at %s has been reinstated'=>'Uanachama wako katika %s umerejeshwa','Your membership at %s has been suspended'=>'Uanachama wako katika %s umesimamishwa','Your membership at %s has been suspended.'=>'Uanachama wako katika %s umesitishwa.','Your message may be reviewed by an automated content filter before being sent to the artist.'=>'Ujumbe wako unaweza kukaguliwa na kichujio cha maudhui cha kiotomatiki kabla ya kutumwa kwa msanii.','Your message to the community had no subject or message text that could be found — this often happens when an email client sends an HTML-only message with no plain-text version included. It was not sent to anyone.'=>'Ujumbe wako kwa jamii haukuwa na mada wala maandishi ya ujumbe yanayoweza kupatikana — mara nyingi hili hutokea barua pepe mteja anapotuma ujumbe wa HTML pekee bila toleo la maandishi ya kawaida kujumuishwa. Haukutumwa kwa yeyote.','Your message to the community was %1$d characters long — the current limit is %2$d. It was not sent to anyone.'=>'Ujumbe wako kwa jamii ulikuwa na herufi %1$d — kikomo cha sasa ni %2$d. Haukutumwa kwa yeyote.','Your name'=>'Jina lako','Your name (optional)'=>'Jina lako (hiari)','Your previous submission is saved in your submissions page in case you want to review what was sent.'=>'Uwasilishaji wako wa awali umehifadhiwa kwenye ukurasa wako wa uwasilishaji iwapo ungependa kupitia ulichotuma.','Your submission has been processed. Here\'s what our AI curator came up with — take a look and let us know if it\'s ready to publish.'=>'Uwasilishaji wako umeshughulikiwa. Hivi ndivyo mhariri wetu wa AI alivyokuja navyo — itazame na utujulishe kama iko tayari kuchapishwa.','Your submissions:'=>'Uwasilishaji wako:','Your temporary suspension at %s has ended and your membership has been reinstated. You can now log in and submit work as before.'=>'Kusitishwa kwako kwa muda katika %s kumemalizika na uanachama wako umewekwa tena. Sasa unaweza kuingia na kuwasilisha kazi kama awali.','Your vote will be recorded once you confirm below.'=>'Kura yako itarekodiwa mara tu utakapothibitisha hapa chini.','— None (inline message only) —'=>'— Hakuna (ujumbe wa ndani pekee) —','— Not set —'=>'— Haijawekwa —','…and %d more.'=>'…na %d zaidi.' . "\0" . '…na %d zaidi.','← Newer'=>'← Mapya zaidi','⚠ %d bounce'=>'⚠ %d upokeaji uliorudi' . "\0" . '⚠ %d upokeaji zilizorudi','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ Tumia tu kama suluhisho la muda wakati cheti cha seva yako ya barua bado hakijaaminika (mf. cheti cha Plesk kilichojisaini kabla ya Let\'s Encrypt kutumika kwa daemoni ya barua). Zima hili pindi seva ya barua inapotoa cheti halali.','✦ Agnosis Gallery Overview — rendered on the server'=>'✦ Muhtasari wa Ghala la Agnosis — hutolewa kwenye seva','💡 Quick tips for a great artwork photo'=>'💡 Vidokezo vya haraka kwa picha nzuri ya kazi ya sanaa','💡 This looked like a reply or forward — we found and used your own text (or attachment) above the quoted part. Next time, starting a brand new email to the same address works best.'=>'💡 Hii ilionekana kama jibu au usambazaji — tulipata na kutumia maandishi yako mwenyewe (au kiambatisho) juu ya sehemu iliyotajwa. Wakati ujao, kuanza barua pepe mpya kabisa kwenda kwenye anwani ile ile ndilo suluhisho bora.','📄 This was published as a new post'=>'📄 Hii ilichapishwa kama chapisho jipya','📬 Vote digest mode'=>'📬 Hali ya muhtasari wa kura','📷 Photo enhanced automatically'=>'📷 Picha imeboreshwa kiotomatiki','📷 Photo quality score: %d / 10'=>'📷 Alama ya ubora wa picha: %d / 10','📷 Photo quality score: %d/10'=>'📷 Alama ya ubora wa picha: %d/10','🔇 Broadcasts muted'=>'🔇 Matangazo yamenyamazishwa','🔗 A link was not included'=>'🔗 Kiungo hakikujumuishwa' . "\0" . '🔗 Baadhi ya viungo havikujumuishwa']];
